import {IonIcon} from '@ionic/react';
import Link, {ThLink} from '../../components/Link';
import ScrollContainer from '../../components/ScrollContainer';
import InnerLink from '../../components/InnerLink';
const _aquakinetcist = {title: "Aquakinetcist", jsx: <><h2 id="arc-kineticist-aquakinetcist-aquakinetcist">Aquakinetcist</h2>
<p><strong>Sources</strong> <Link to="/source/aquatic_adventures">Aquatic Adventures pg. 50</Link><br/>While all hydrokineticists have the ability to control water, aquakineticists' powers are tied to their determination to explore the world beneath the waves.</p>
<div className="ability p"><div className="abIcon"><Link to="/icons/info"><IonIcon icon="/icons/info.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-kineticist-aquakinetcist-aquatic-focus" data-hash-target><div className="box">Aquatic Focus</div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Alters</div></div><div className="abEnd"><div className="box">Expanded element</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Info</div></div><div className="abEnd"><div className="box">An aquakineticist must choose water as her primary <Link to="/ability/elements">element</Link> and for both <em>expanded elements,</em> and must choose <Link to="/kinetic/water_blast">water blast</Link> as her first simple blast.</div></div></div></div>
<div className="ability p"><div className="abIcon"><Link to="/icons/magic-swirl"><IonIcon icon="/icons/magic-swirl.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-kineticist-aquakinetcist-basis-aquakinesis-sp" data-hash-target><div className="box">Basis Aquakinesis (Sp)</div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Replaces</div></div><div className="abEnd"><div className="box">Basic hydrokinesis</div></div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Alters</div></div><div className="abEnd"><div className="box">Elemental focus</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Ability</div></div><div className="abEnd"><div className="box">An aquakineticist can create mild currents, as per <Link to="/kinetic/basic_hydrokinesis">basic hydrokinesis</Link>. Additionally, she can adjust her <Link to="/rule/buoyancy">buoyancy</Link> to whatever level she wishes as a <strong className="hl">standard action</strong>, lasting until she uses basic aquakinesis again.</div></div></div></div>
<div className="ability p"><div className="abIcon"><Link to="/icons/stairs-goal"><IonIcon icon="/icons/stairs-goal.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-kineticist-aquakinetcist-call-of-the-deep" data-hash-target><div className="box">Call of the Deep</div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Replaces</div></div><div className="abEnd"><div className="box">2nd and 6th level utility wild talents</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">At 2nd Level</div></div><div className="abEnd"><div className="box">An aquakineticist gains <Link to="/kinetic/waterdancer">waterdancer</Link> as a bonus utility wild talent.</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">At 6th Level</div></div><div className="abEnd"><div className="box">She gains <Link to="/kinetic/watersense">watersense</Link> as a bonus utility wild talent, and she can choose to ignore the effects of <Link to="/rule/currents">currents</Link> with speeds up to 60 feet while her <em>waterdancer</em> ability is active.</div></div></div></div>
<div className="ability p"><div className="abIcon"><Link to="/icons/stairs-goal"><IonIcon icon="/icons/stairs-goal.svg" color="secondary" /></Link><Link to="/icons/armor-upgrade"><IonIcon icon="/icons/armor-upgrade.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-kineticist-aquakinetcist-oceans-caress-su" data-hash-target><div className="box">Ocean's Caress (Su)</div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Replaces</div></div><div className="abEnd"><div className="box">Defense wild talent from elemental defense</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Gained</div></div><div className="abEnd"><div className="box">At 2nd Level</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Ability</div></div><div className="abEnd"><div className="box">An aquakineticist can breathe underwater as easily as she breathes air, and she gains <Link to="/kinetic/cold_adaptation">cold adaptation</Link> as a bonus utility wild talent, adding half her kineticist level to her cold <Link to="/umr/resistance">resistance</Link> from cold adaptation. By accepting 1 point of burn, she can increase her cold resistance by an additional 3, stacking with the resistance she gains from cold adaptation. If her total cold resistance from this ability would ever be 40 or higher, she gains cold <Link to="/umr/immunity">immunity</Link> instead. All cold resistance and immunity from this ability also applies to <Link to="/rule/pressure_damage">pressure damage</Link>, and she <Link to="/rule/pressure">adjusts to a new pressure</Link> all at once after making five Fortitude saves, rather than 100 feet at a time. Whenever she accepts burn while using a water wild talent, the water coalescing around her doubles her cold resistance for 1 round (which might trigger cold immunity). She can dismiss or restore this effect as an <strong className="hl">immediate action</strong>.</div></div></div></div>
<div className="ability p"><div className="abIcon"><Link to="/icons/stairs-goal"><IonIcon icon="/icons/stairs-goal.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-kineticist-aquakinetcist-ice-propagation-su" data-hash-target><div className="box">Ice Propagation (Su)</div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Alters</div></div><div className="abEnd"><div className="box">Cold simple blast</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Gained</div></div><div className="abEnd"><div className="box">At 7th Level</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Ability</div></div><div className="abEnd"><div className="box">An aquakineticist's connection to the water around her allows her greater control over the ice formed by her cold attacks. When using her cold blast underwater (which <Link to="/rule/spells">freezes water into ice</Link> and deals half piercing damage), she can make the cold blast a physical blast and apply any form or substance infusions that she could apply to an ice composite blast. This still deals damage as per a simple physical blast, not a composite blast.</div></div></div></div>
</>};
const _arakineticist = {title: "Arakineticist", jsx: <><h2 id="arc-kineticist-arakineticist-arakineticist">Arakineticist</h2>
<p><strong>Sources</strong> <Link to="/source/blood_of_the_coven">Blood of the Coven pg. 22</Link><br/>Those of strong will who live under a dark curse long enough might learn to control and channel the corrupt energy afflicting them. <Link to="/race/changeling">Changelings</Link> who resist the call of their hag mothers are especially given to the arts of the arakineticist.</p>
<div className="ability p"><div className="abIcon"><Link to="/icons/info"><IonIcon icon="/icons/info.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-kineticist-arakineticist-living-curse" data-hash-target><div className="box">Living Curse</div></div>
<div className="abPair"><div className="abStart"><div className="box">Info</div></div><div className="abEnd"><div className="box">An arakineticist's curse lives within her, granting her dark powers. She must choose void as her primary <Link to="/ability/elements">element</Link> and <Link to="/kinetic/negative_blast">negative blast</Link> as her first simple blast.</div></div></div></div>
<div className="ability p"><div className="abIcon"><Link to="/icons/armor-upgrade"><IonIcon icon="/icons/armor-upgrade.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-kineticist-arakineticist-accursed-shadow-sp" data-hash-target><div className="box">Accursed Shadow (Sp)</div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Replaces</div></div><div className="abEnd"><div className="box">Utility wild talent gained at 4th level</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Gained</div></div><div className="abEnd"><div className="box">At 4th Level</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Passive Ability</div></div><div className="abEnd"><div className="box">An arakineticist's curse casts a dark shadow over her soul, shielding her from death magic. She gains a bonus on saving throws against necromancy spells and death effects. This bonus is equal to 1 + <Link to="/misc/one_fourth">one-fourth</Link> of her kineticist level.</div></div></div></div>
<div className="ability p"><div className="abIcon"><Link to="/icons/magic-swirl"><IonIcon icon="/icons/magic-swirl.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-kineticist-arakineticist-curse-spinner-sp" data-hash-target><div className="box">Curse Spinner (Sp)</div><div className="flavor">An arakineticist learns to wield her living curse like a needle to weave and unravel curses.</div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Replaces</div></div><div className="abEnd"><div className="box">Utility wild talents gained at 6th and 8th levels</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">At 6th Level</div></div><div className="abEnd"><div className="box">An arakineticist can accept 1 point of burn to cast <Link to="/spell/remove_curse">remove curse</Link> as a spell-like ability.</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">At 8th Level</div></div><div className="abEnd"><div className="box">She can accept 1 point of burn to curse a target as <Link to="/spell/bestow_curse">bestow curse</Link> as spell-like ability.</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Special</div></div><div className="abEnd"><div className="box">Both of these abilities count as 4th-level utility wild talents.</div></div></div></div>
<div className="ability p"><div className="abIcon"><Link to="/icons/armor-downgrade"><IonIcon icon="/icons/armor-downgrade.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-kineticist-arakineticist-accursed-infusion-su" data-hash-target><div className="box">Accursed Infusion (Su)</div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Replaces</div></div><div className="abEnd"><div className="box">Utility wild talent gained at 13th level</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Gained</div></div><div className="abEnd"><div className="box">At 13th Level</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Ability</div></div><div className="abEnd"><div className="box">An arakineticist's blasts can temporarily curse and bedevil her foe. On a failed Will save, the target takes a -4 penalty on ability checks, attack rolls, saving throws, and skills checks for 1 round as if it were affected by <em>bestow curse.</em> A single creature can't be affected by more than one curse from this infusion at a time.</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Special</div></div><div className="abEnd"><div className="box">This is a 6th-level substance infusion that costs 4 points of burn and can be used with <em>negative</em> and <em>void blasts.</em></div></div></div></div>
</>};
const _blightburner = {title: "Blightburner", jsx: <><h2 id="arc-kineticist-blightburner-blightburner">Blightburner</h2>
<p><strong>Sources</strong> <Link to="/source/heroes_of_the_darklands">Heroes of the Darklands pg. 25</Link><br/>Darklands geokineticists sometimes exhibit supernatural powers associated with <Link to="/eq-material/blightburn">blightburn</Link> crystals. Blightburner kineticists harness this radioactivity in pyrotechnic displays, an unusual feat for those connected to the element of earth.</p>
<div className="ability p"><div className="abIcon"><Link to="/icons/info"><IonIcon icon="/icons/info.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-kineticist-blightburner-earth-focus" data-hash-target><div className="box">Earth Focus</div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Alters</div></div><div className="abEnd"><div className="box">Elemental focus</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Info</div></div><div className="abEnd"><div className="box">A blightburner must choose earth as her <Link to="/ability/elements">elemental</Link> focus.</div></div></div></div>
<div className="ability p"><div className="abIcon"><Link to="/icons/magic-swirl"><IonIcon icon="/icons/magic-swirl.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-kineticist-blightburner-blightburn-manipulation-su" data-hash-target><div className="box">Blightburn Manipulation (Su)</div><div className="flavor">A blightburner can harness radiation for nondestructive purposes.</div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Replaces</div></div><div className="abEnd"><div className="box"><em>Basic geokinesis</em> wild talent</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Standard Action</div></div><div className="abEnd"><div className="box">A blightburner can channel blightburn radiation, causing herself to glow like a <Link to="/eq-misc/torch">torch</Link>. This effect lasts until she dismisses it as another standard action. Additionally, she can generate small amounts of heat with her hands. This radiation can slowly heat unattended objects with a touch to a warm (but not painfully hot) temperature, or cook raw meat or vegetable matter at a rate of 1 pound per minute. If used on a living creature, this ability deals 1 point of nonlethal damage per minute of contact, which manifests as reddened and blistering skin.</div></div></div></div>
<div className="ability p"><div className="abIcon"><Link to="/icons/armor-upgrade"><IonIcon icon="/icons/armor-upgrade.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-kineticist-blightburner-radiation-absorption-su" data-hash-target><div className="box">Radiation Absorption (Su)</div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Replaces</div></div><div className="abEnd"><div className="box">Utility wild talent gained at 2nd level</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Gained</div></div><div className="abEnd"><div className="box">At 2nd Level</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Ability</div></div><div className="abEnd"><div className="box">Whenever a blightburner would take <Link to="/rule/ability_damage">ability damage</Link> from radiation, she can accept 1 point of burn to reduce the ability damage by 4 points. Any remaining ability damage is applied normally.</div></div></div></div>
<div className="ability p"><div className="abIcon"><Link to="/icons/stairs-goal"><IonIcon icon="/icons/stairs-goal.svg" color="secondary" /></Link><Link to="/icons/armor-upgrade"><IonIcon icon="/icons/armor-upgrade.svg" color="secondary" /></Link><Link to="/icons/abstract-091"><IonIcon icon="/icons/abstract-091.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-kineticist-blightburner-blightburn-aura-su" data-hash-target><div className="box">Blightburn Aura (Su)</div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Replaces</div></div><div className="abEnd"><div className="box">Ability score boosts granted by elemental overflow, earth's elemental defense</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Gained</div></div><div className="abEnd"><div className="box">At 2nd Level</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Ability</div></div><div className="abEnd"><div className="box">A blightburner's body surges with a greenish, radioactive glow whenever she accepts burn. This energy sheds light like a <Link to="/eq-misc/candle">candle</Link>. A creature that hits the blightburner with a natural attack, unarmed strike, or non-reach melee weapon attack while she's under the effect of her <em>blightburn aura</em> takes fire damage equal to her <em>elemental overflow</em> bonus (minimum 1). By accepting 2 points of burn, she can increase this damage by an amount equal to her <em>elemental overflow</em> bonus; she can increase the damage in this way up to four times. A blightburner can temporarily suppress the visual effects of a <em>blightburn aura</em> by concentrating for 1 full round, but doing so also suppresses all of this ability's other benefits. The next time she uses a wild talent, the visual effects and benefits return instantly.</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">At 6th Level</div></div><div className="abEnd"><div className="box">Whenever the blightburner has at least 3 points of burn, the <em>blightburn aura</em> expands to fill all adjacent squares. In addition to damaging creatures that hit the blightburner with melee attacks, the aura also deals damage to other creatures that end their turns within the aura.</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">At 11th Level</div></div><div className="abEnd"><div className="box">Whenever the kineticist has at least 5 points of burn, the <em>blightburn aura</em> expands to a 10-foot-radius aura, and any creature that takes damage from it must also succeed at a Fortitude save (DC = 10 + half the blightburner's level + her Constitution bonus) or be <Link to="/misc/sickened">sickened</Link> for 1 round. This ability is a poison effect.</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">At 16th Level</div></div><div className="abEnd"><div className="box">Whenever a blightburner has at least 7 points of burn, any creature that takes damage from the <em>blightburn aura</em> and fails its Fortitude save also become <Link to="/misc/fatigued">fatigued</Link>.</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Special</div></div><div className="abEnd"><div className="box">The blightburner can still gain elemental defenses from other elements with <em>expanded defense.</em></div></div></div></div>
<div className="ability p"><div className="abIcon"><Link to="/icons/armor-upgrade"><IonIcon icon="/icons/armor-upgrade.svg" color="secondary" /></Link><Link to="/icons/upgrade"><IonIcon icon="/icons/upgrade.svg" color="secondary" /></Link><Link to="/icons/broken-shield"><IonIcon icon="/icons/broken-shield.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-kineticist-blightburner-radiation-resistance-su" data-hash-target><div className="box">Radiation Resistance (Su)</div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Alters</div></div><div className="abEnd"><div className="box">Gather power, internal buffer</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Gained</div></div><div className="abEnd"><div className="box">At 6th Level</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Ability</div></div><div className="abEnd"><div className="box">A blightburner becomes resistant to all forms of radiation, and can use the radiation's energy as gathered power. She gains a bonus on saving throws to resist the effects of radiation equal to her <em>elemental overflow</em> bonus. When she succeeds at a save against radiation, she can reduce the total burn cost of a blast wild talent used before the end of her next turn as if she had gathered power with a move action. Once she gains this benefit, she can't do so again for 1 minute, even if she's exposed to radiation again before that. She can't use this ability if she's immune to poison or radiation.</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">At 11th Level</div></div><div className="abEnd"><div className="box">A blightburner gains an <em>internal buffer</em> at 11th level, and it has a capacity as if she were 5 levels lower.</div></div></div></div>
</>};
const _blighted_defiler = {title: "Blighted Defiler", jsx: <><h2 id="arc-kineticist-blighted_defiler-blighted-defiler">Blighted Defiler</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_wilderness">Ultimate Wilderness pg. 62</Link><br/>A few kineticists have developed the ability to steal the life force from the surrounding land in order to infuse themselves with unnatural strength beyond their bodies' normal capabilities.</p>
<div className="ability p"><div className="abIcon"><Link to="/icons/hazard-sign"><IonIcon icon="/icons/hazard-sign.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-kineticist-blighted_defiler-alignment" data-hash-target><div className="box">Alignment</div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Alters</div></div><div className="abEnd"><div className="box">Alignment</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Info</div></div><div className="abEnd"><div className="box">Blighted defilers must be evil in order to use <em>steal power,</em> since defiling the land and reaping the vulnerable for power is a particularly vile act. Nonevil blighted defilers can continue to gain kineticist levels and use their other abilities.</div></div></div></div>
<div className="ability p"><div className="abIcon"><Link to="/icons/magic-swirl"><IonIcon icon="/icons/magic-swirl.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-kineticist-blighted_defiler-steal-power-su" data-hash-target><div className="box">Steal Power (Su)</div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Alters</div></div><div className="abEnd"><div className="box">Gather power</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Usage</div></div><div className="abEnd"><div className="box">Strength modifier times/day</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Ability</div></div><div className="abEnd"><div className="box"><p>A blighted defiler can draw energy from the surrounding land to <em>gather power,</em> gaining one of the three following benefits.</p>
<ol>
<li>She can increase the burn reduction from <em>gather power</em> by 1 for a blast wild talent.</li>
<li>Alternatively, she can use <em>gather power</em> to reduce the cost of a defense, infusion, or utility wild talent by 1, regardless of whether she <em>gathers power</em> for longer or has abilities that increase the burn reduction from <em>gather power.</em></li>
<li>Finally, she can siphon the energy into healing herself, recovering 2 hit points per kineticist level.</li>
</ol>
<p>When a blighted defiler uses <em>steal power,</em> she afflicts the area within a radius of 250 feet per kineticist level (maximum 5,000 feet at 20th level) by stunting plants as the stunt growth option from <Link to="/spell/diminish_plants">diminish plants</Link>, weakening and killing minor wildlife (creatures too small or insignificant to themselves have statistics), and reducing the rate of live birth among the other surviving creatures in the area. If a blighted defiler uses <em>steal power</em> in an area that overlaps a previous use of her <em>steal power</em> within the same month, she expends a daily use and the remaining area is still blighted as above, but she doesn't gain any benefits. <em>Steal power</em> doesn't work in barren landscapes, the void of space, or other places without enough life to steal.</p>
</div></div></div></div>
<div className="ability p"><div className="abIcon"><Link to="/icons/info"><IonIcon icon="/icons/info.svg" color="secondary" /></Link><Link to="/icons/upgrade"><IonIcon icon="/icons/upgrade.svg" color="secondary" /></Link><Link to="/icons/broken-shield"><IonIcon icon="/icons/broken-shield.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-kineticist-blighted_defiler-elemental-might-ex" data-hash-target><div className="box">Elemental Might (Ex)</div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Alters</div></div><div className="abEnd"><div className="box">The key ability score of wild talents, elemental overflow</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Info</div></div><div className="abEnd"><div className="box"><p>A blighted defiler uses her Strength modifier instead of her Constitution modifier to determine her damage with wild talents, the DCs of Constitution-based wild talents, the durations of wild talents with Constitution-based durations, her bonus on <Link to="/rule/concentration">concentration</Link> checks for wild talents, and other Constitution-based effects of her wild talents. She can't use abilities to substitute her Strength modifier for another ability score when determining damage from wild talents.</p>
<p>A blighted defiler gains attack and damage bonuses from <em>elemental overflow</em> based on her current burn total + the number of times she successfully used <em>steal power</em> that day. For instance, a 9th-level blighted defiler who used <em>steal power</em> twice and had 1 point of burn would add a +3 bonus on attack rolls and a +6 bonus on damage rolls. A blighted defiler does not gain size bonuses to physical ability scores or a chance to ignore critical hits and sneak attacks from <em>elemental overflow.</em></p>
</div></div></div></div>
<div className="ability p"><div className="abIcon"><Link to="/icons/stairs-goal"><IonIcon icon="/icons/stairs-goal.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-kineticist-blighted_defiler-life-buffer-su" data-hash-target><div className="box">Life Buffer (Su)</div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Replaces</div></div><div className="abEnd"><div className="box">Internal buffer</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Gained</div></div><div className="abEnd"><div className="box">At 6th Level</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Ability</div></div><div className="abEnd"><div className="box">A blighted defiler gains a <em>buffer</em> she can use to store life potential from healthy areas in order to use it later. She must use <em>steal power</em> on a healthy area and take none of the three usual benefits, and this doesn't count as a use of <em>steal power</em> for elemental might or stolen strength. This grants her <em>buffer</em> 1 life point. When using <em>steal power,</em> she can spend 1 life point to gain the benefits even in an area she already blighted that month. Life points remain in the <em>buffer</em> until she spends them.</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">At 6th Level</div></div><div className="abEnd"><div className="box">The <em>buffer</em> can hold a maximum of 1 life point.</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">At 11th Level</div></div><div className="abEnd"><div className="box">It can now hold 2 life points.</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">At 16th Level</div></div><div className="abEnd"><div className="box">It can now hold 3 life points.</div></div></div></div>
<div className="ability p"><div className="abIcon"><Link to="/icons/upgrade"><IonIcon icon="/icons/upgrade.svg" color="secondary" /></Link><Link to="/icons/broken-shield"><IonIcon icon="/icons/broken-shield.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-kineticist-blighted_defiler-stolen-strength-su" data-hash-target><div className="box">Stolen Strength (Su)</div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Replaces</div></div><div className="abEnd"><div className="box">Elemental defense</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Gained</div></div><div className="abEnd"><div className="box">At 6th Level</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Ability</div></div><div className="abEnd"><div className="box">A blighted defiler gains the ability to collect unused portions of the life she's stolen throughout the day to bolster herself. After the third time she successfully uses <em>steal power</em> in a given day, she gains a +2 size bonus to Strength and to either Dexterity or Constitution until she recovers uses of <em>steal power.</em></div></div></div>
<div className="abPair"><div className="abStart"><div className="box">At 11th Level</div></div><div className="abEnd"><div className="box">After the fifth time the blighted defender successfully uses <em>steal power</em> in a day, she instead gains a +4 size bonus to Strength and a +2 size bonus to Dexterity and Constitution, and she can use the life energy to increase her size category by one (to a maximum of Large).</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">At 16th Level</div></div><div className="abEnd"><div className="box">After the seventh time the blighted defender successfully uses <em>steal power</em> in a day, her size bonuses increase to +6 to Strength, +4 to either Dexterity or Constitution, and +2 to the remaining ability score, and she can also grow to Huge.</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">At 20th Level</div></div><div className="abEnd"><div className="box">After the 9th time she successfully uses <em>steal power</em> in a day, she can also grow to Gargantuan.</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Special</div></div><div className="abEnd"><div className="box">All of these size increases function as <Link to="/kinetic/kinetic_form">kinetic form</Link>, meaning they don't change her ability scores in any way. A blighted defiler can never gain an elemental defense, even from <em>expanded defense.</em></div></div></div></div>
<div className="ability p"><div className="abIcon"><Link to="/icons/smoking-finger"><IonIcon icon="/icons/smoking-finger.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-kineticist-blighted_defiler-steal-life-su" data-hash-target><div className="box">Steal Life (Su)</div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Replaces</div></div><div className="abEnd"><div className="box">Omnikinesis</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Gained</div></div><div className="abEnd"><div className="box">At 20th Level</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Ability</div></div><div className="abEnd"><div className="box">A blighted defiler who successfully uses <em>steal power</em> when <em>gathering power</em> as a move action can use a <strong className="hl">standard action</strong> on the same turn and choose a living creature within 30 feet. The creature must succeed at a Fortitude save (DC = 20 + the blighted defiler's Strength modifier) or die; this is a death effect. If the creature dies and was CR 10 or higher, on the blighted defiler's next turn, she counts as if she had used a full round to <em>gather power</em> with <em>steal power.</em> If the target survives or was lower than CR 10, she loses all benefits from both her <em>gather power</em> and <em>steal power,</em> as normal at the end of her turn.</div></div></div></div>
</>};
const _blood_kineticist = {title: "Blood Kineticist", jsx: <><h2 id="arc-kineticist-blood_kineticist-blood-kineticist">Blood Kineticist</h2>
<p><strong>Sources</strong> <Link to="/source/occult_adventures">Occult Adventures pg. 88</Link><br/>To a blood kineticist, the water in a creature's blood is just like any other sort, and she uses that knowledge to brutal ends.</p>
<div className="ability p"><div className="abIcon"><Link to="/icons/info"><IonIcon icon="/icons/info.svg" color="secondary" /></Link><Link to="/icons/hazard-sign"><IonIcon icon="/icons/hazard-sign.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-kineticist-blood_kineticist-blood-focus-ex" data-hash-target><div className="box">Blood Focus (Ex)</div></div>
<div className="abPair"><div className="abStart"><div className="box">Info</div></div><div className="abEnd"><div className="box">A blood kineticist must choose water as her primary <Link to="/ability/elements">element</Link> and must choose <Link to="/kinetic/water_blast">water blast</Link> as her first simple blast. All of her infusions granted by this archetype work only on targets with blood and automatically fail if the target is immune to <Link to="/rule/bleed">bleed</Link> damage.</div></div></div></div>
<div className="ability p"><div className="abIcon"><Link to="/icons/smoking-finger"><IonIcon icon="/icons/smoking-finger.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-kineticist-blood_kineticist-wrack-su" data-hash-target><div className="box">Wrack (Su)</div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Replaces</div></div><div className="abEnd"><div className="box">The 1st-level infusion</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Gained</div></div><div className="abEnd"><div className="box">At 1st Level</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Ability</div></div><div className="abEnd"><div className="box">A blood kineticist can use her abilities to wrack a target within 30 feet, harming the target by manipulating its blood from the inside. The target takes half the normal damage of the blood kineticist's blast, and can attempt a Fortitude save to reduce that amount to 1/4 normal damage, but the damage is untyped and ignores damage reduction.</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Special</div></div><div className="abEnd"><div className="box">This is a 1st-level form infusion that costs 0 points of burn and can be used with water and blood blasts.</div></div></div></div>
<div className="ability p"><div className="abIcon"><Link to="/icons/upgrade"><IonIcon icon="/icons/upgrade.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-kineticist-blood_kineticist-bleeding-infusion-su" data-hash-target><div className="box">Bleeding Infusion (Su)</div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Replaces</div></div><div className="abEnd"><div className="box">The 5th-level infusion</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Gained</div></div><div className="abEnd"><div className="box">At 5th Level</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Ability</div></div><div className="abEnd"><div className="box">A blood kineticist can infuse her blasts with a vicious power that causes internal or external bleeding. On a failed Fortitude save, the target takes 1 point of bleed damage for every die of the blast's damage. A target that fails its saving throw against the wrack form infusion does not receive a saving throw to avoid the bleed damage from bleeding infusion on the same blast.</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Special</div></div><div className="abEnd"><div className="box">This is a 2nd-level substance infusion that costs 2 points of burn and can be used with water and blood blasts.</div></div></div></div>
<div className="ability p"><div className="abIcon"><Link to="/icons/magic-swirl"><IonIcon icon="/icons/magic-swirl.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-kineticist-blood_kineticist-blood-tell-sp" data-hash-target><div className="box">Blood Tell (Sp)</div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Replaces</div></div><div className="abEnd"><div className="box">The 6th-level utility wild talent</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Gained</div></div><div className="abEnd"><div className="box">At 6th Level</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Ability</div></div><div className="abEnd"><div className="box">A blood kineticist's connection to blood allows her to learn much from the blood of another. This works as <Link to="/spell/blood_biography">blood biography</Link>, except the blood kineticist suddenly knows the information, rather than having it appear on a parchment.</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Special</div></div><div className="abEnd"><div className="box">This is a 3rd-level utility wild talent and costs 0 points of burn. She can accept 1 point of burn to reduce the casting time to a <strong className="hl">standard action</strong> instead of 1 minute.</div></div></div></div>
<div className="ability p"><div className="abIcon"><Link to="/icons/stairs-goal"><IonIcon icon="/icons/stairs-goal.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-kineticist-blood_kineticist-blood-blast-su" data-hash-target><div className="box">Blood Blast (Su)</div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Alters</div></div><div className="abEnd"><div className="box">Expanded element</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Info</div></div><div className="abEnd"><div className="box">The first time a blood kineticist selects water with <em>expanded element,</em> she doesn't gain the <Link to="/kinetic/cold_blast">cold simple blast</Link> or the <Link to="/kinetic/ice_blast">ice composite blast</Link>; instead, she gains the <em>blood composite blast,</em> which costs 2 points of burn. A <em>blood blast</em> is a physical blast that deals bludgeoning damage. It is associated with the same infusions as the <em>water blast.</em> If the blood kineticist selects water with <em>expanded element</em> a second time, she gains the <em>cold blast</em> and <em>ice blast</em> as normal.</div></div></div></div>
<div className="ability p"><div className="abIcon"><Link to="/icons/stairs-goal"><IonIcon icon="/icons/stairs-goal.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-kineticist-blood_kineticist-blood-throw-su" data-hash-target><div className="box">Blood Throw (Su)</div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Replaces</div></div><div className="abEnd"><div className="box">The 8th-level utility wild talent</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Gained</div></div><div className="abEnd"><div className="box">At 8th Level</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Ability</div></div><div className="abEnd"><div className="box">A blood kineticist gains the <Link to="/kinetic/foe_throw">foe throw</Link> infusion as a bonus infusion, and can use it with the water element on water and blood blasts, in addition to its normal associated element and blast.</div></div></div></div>
<div className="ability p"><div className="abIcon"><Link to="/icons/armor-downgrade"><IonIcon icon="/icons/armor-downgrade.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-kineticist-blood_kineticist-gut-wrenching-infusion-su" data-hash-target><div className="box">Gut-Wrenching Infusion (Su)</div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Replaces</div></div><div className="abEnd"><div className="box">The 9th-level infusion</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Gained</div></div><div className="abEnd"><div className="box">At 9th Level</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Ability</div></div><div className="abEnd"><div className="box">A blood kineticist can infuse her blasts with the ability to manipulate her opponent's insides to the point of impairing their function. On a failed Fortitude save, the target is <Link to="/misc/sickened">sickened</Link> for 1 minute. A target that fails its saving throw against the wrack form infusion does not receive a saving throw to avoid the sickened condition from <em>gut-wrenching infusion</em> on the same blast.</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Special</div></div><div className="abEnd"><div className="box">This is a 4th-level substance infusion that costs 3 points of burn and can be used with water and blood blasts.</div></div></div></div>
<div className="ability p"><div className="abIcon"><Link to="/icons/stairs-goal"><IonIcon icon="/icons/stairs-goal.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-kineticist-blood_kineticist-vampiric-infusion-su" data-hash-target><div className="box">Vampiric Infusion (Su)</div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Replaces</div></div><div className="abEnd"><div className="box">The 11th-level infusion</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Gained</div></div><div className="abEnd"><div className="box">At 11th Level</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Ability</div></div><div className="abEnd"><div className="box">A blood kineticist can drain the vitality from her enemy's blood to restore her own. If her blast hits (or the enemy fails its saving throw against a blast without an attack roll) the blood kineticist can activate the <Link to="/kinetic/kinetic_healer">kinetic healer</Link> utility wild talent on herself by accepting its burn cost; she doesn't need to take an action to do so. If she doesn't possess the <em>kinetic healer</em> utility wild talent, she can still use this ability, but it heals only half as much.</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Special</div></div><div className="abEnd"><div className="box">This is a 5th-level substance infusion that costs 3 points of burn and can be used with water and blood blasts.</div></div></div></div>
<div className="ability p"><div className="abIcon"><Link to="/icons/armor-upgrade"><IonIcon icon="/icons/armor-upgrade.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-kineticist-blood_kineticist-blood-mastery-su" data-hash-target><div className="box">Blood Mastery (Su)</div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Replaces</div></div><div className="abEnd"><div className="box">Omnikinesis</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Gained</div></div><div className="abEnd"><div className="box">At 20th Level</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Passive Ability</div></div><div className="abEnd"><div className="box">A blood kineticist no longer ages and can't be magically aged. She doesn't take penalties to her ability scores for <Link to="/rule/aging">aging</Link> and removes any such penalties she already possesses. She still accrues age bonuses as normal, but she doesn't die of old age when her time would be up. Because of her utter control over her own blood, she is immune to bleed, injected poisons, injury diseases, and the sickened and <Link to="/misc/nauseated">nauseated</Link> conditions unless she chooses to be affected.</div></div></div></div>
</>};
const _cinderlands_adept = {title: "Cinderlands Adept", jsx: <><h2 id="arc-kineticist-cinderlands_adept-cinderlands-adept">Cinderlands Adept</h2>
<p><strong>Sources</strong> <Link to="/source/wilderness_origins">Wilderness Origins pg. 28</Link><br/>Among the Sun Clan's most noted champions are those who can tame the flames and bend them to their will. These kineticists are skilled riders, able to wield both weapons and fire with deadly skill.</p>
<div className="ability p"><div className="abIcon"><Link to="/icons/skills"><IonIcon icon="/icons/skills.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-kineticist-cinderlands_adept-undefined" data-hash-target><div className="box">Class Skills</div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Alters</div></div><div className="abEnd"><div className="box">Class skills</div></div></div><div className="abPair"><div className="abStart"><div className="box">New Class Skills</div></div><div className="abEnd"><div className="box"><Link to="/skill/handle_animal">Handle Animal</Link> (CHA), <Link to="/skill/ride">Ride</Link> (DEX)</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Removed Skills</div></div><div className="abEnd"><div className="box">Stealth, Use Magic Device</div></div></div></div>
<div className="ability p"><div className="abIcon"><Link to="/icons/info"><IonIcon icon="/icons/info.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-kineticist-cinderlands_adept-fire-focus-su" data-hash-target><div className="box">Fire Focus (Su)</div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Alters</div></div><div className="abEnd"><div className="box">Elemental focus, expanded element</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Info</div></div><div className="abEnd"><div className="box">When a Cinderlands adept gains <em>elemental focus,</em> she must select fire (pyrokinesis) as her chosen <Link to="/ability/elements">element</Link>. When she gains the <em>expanded element</em> class feature at 7th and 15th levels, she must select her primary element of fire and does not learn to use a new element.</div></div></div></div>
<div className="ability p"><div className="abIcon"><Link to="/icons/stairs-goal"><IonIcon icon="/icons/stairs-goal.svg" color="secondary" /></Link><Link to="/icons/upgrade"><IonIcon icon="/icons/upgrade.svg" color="secondary" /></Link><Link to="/icons/armor-upgrade"><IonIcon icon="/icons/armor-upgrade.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-kineticist-cinderlands_adept-galloping-siphon-su" data-hash-target><div className="box">Galloping Siphon (Su)</div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Replaces</div></div><div className="abEnd"><div className="box">Infusion gained at 1st level</div></div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Alters</div></div><div className="abEnd"><div className="box">Gather power</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Ability</div></div><div className="abEnd"><div className="box">A Cinderlands adept gains <Link to="/feat/mounted_combat">Mounted Combat</Link> as a bonus feat and a bonus on <Link to="/rule/concentration">concentration</Link> checks due to riding. This bonus is equal to 1 + <Link to="/misc/one_fourth">one-fourth</Link> of her kineticist level.</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Passive Ability</div></div><div className="abEnd"><div className="box">When a Cinderlands adept <em>gathers power</em> while mounted, she and her mount gain fire <Link to="/umr/resistance">resistance</Link> 5 for a number of rounds equal to the total value of the burn cost she reduces. The Cinderlands adept and her mount lose this resistance if she dismounts before the duration ends.</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">At 11th Level</div></div><div className="abEnd"><div className="box">The resistance granted increases to fire resistance 10.</div></div></div></div>
<div className="ability p"><div className="abIcon"><Link to="/icons/stairs-goal"><IonIcon icon="/icons/stairs-goal.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-kineticist-cinderlands_adept-mount" data-hash-target><div className="box">Mount</div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Replaces</div></div><div className="abEnd"><div className="box">Utility wild talents gained at 4th, 8th, and 12th levels</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Gained</div></div><div className="abEnd"><div className="box">At 4th Level</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Ability</div></div><div className="abEnd"><div className="box">A Cinderlands adept gains a loyal mount. This ability functions like the <Link to="/class/druid">druid's</Link> <Link to="/sidekick/animal_companion">animal companion</Link> ability (as described in the <em>nature bond</em> class feature), except that the Cinderlands adept always gains a <Link to="/companion/horse">horse</Link> or <Link to="/companion/pony">pony</Link> (though she can gain additional options at the GM's discretion) and her effective druid level is equal to her cinterlands adept level - 3.</div></div></div></div>
</>};
const _dark_elementalist = {title: "Dark Elementalist", jsx: <><h2 id="arc-kineticist-dark_elementalist-dark-elementalist">Dark Elementalist</h2>
<p><strong>Sources</strong> <Link to="/source/horror_adventures">Horror Adventures pg. 56</Link><br/>Some kineticists who are loathe to suffer the consequences of channeling their power study the darkest esoteric energies of the planes and use souls to fuel their occult might. The spiritual tortures these dark elementalists inflict upon their victims' souls are horrifically selfish acts on par with the actions of <Link to="/family/daemon">daemons</Link>.</p>
<div className="ability p"><div className="abIcon"><Link to="/icons/hazard-sign"><IonIcon icon="/icons/hazard-sign.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-kineticist-dark_elementalist-alignment" data-hash-target><div className="box">Alignment</div></div>
<div className="abPair"><div className="abStart"><div className="box">Info</div></div><div className="abEnd"><div className="box">Since harming souls is a wicked act, a dark elementalist must be of an evil alignment. If she becomes nonevil, she can't use any of her dark elementalist abilities other than <em>dark studies,</em> though she can still use her other kineticist class features.</div></div></div></div>
<div className="ability p"><div className="abIcon"><Link to="/icons/skills"><IonIcon icon="/icons/skills.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-kineticist-dark_elementalist-undefined" data-hash-target><div className="box">Class Skills</div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Alters</div></div><div className="abEnd"><div className="box">Class skills</div></div></div><div className="abPair"><div className="abStart"><div className="box">New Class Skills</div></div><div className="abEnd"><div className="box"><Link to="/skill/knowledge_arcana">Knowledge (arcana)</Link> (INT), <Link to="/skill/knowledge_dungeoneering">Knowledge (dungeoneering)</Link> (INT), <Link to="/skill/knowledge_engineering">Knowledge (engineering)</Link> (INT), <Link to="/skill/knowledge_geography">Knowledge (geography)</Link> (INT), <Link to="/skill/knowledge_history">Knowledge (history)</Link> (INT), <Link to="/skill/knowledge_local">Knowledge (local)</Link> (INT), <Link to="/skill/knowledge_nature">Knowledge (nature)</Link> (INT), <Link to="/skill/knowledge_nobility">Knowledge (nobility)</Link> (INT), <Link to="/skill/knowledge_planes">Knowledge (planes)</Link> (INT), <Link to="/skill/knowledge_religion">Knowledge (religion)</Link> (INT)</div></div></div></div>
<div className="ability p"><div className="abIcon"><Link to="/icons/armor-upgrade"><IonIcon icon="/icons/armor-upgrade.svg" color="secondary" /></Link><Link to="/icons/broken-shield"><IonIcon icon="/icons/broken-shield.svg" color="secondary" /></Link><Link to="/icons/info"><IonIcon icon="/icons/info.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-kineticist-dark_elementalist-dark-studies" data-hash-target><div className="box">Dark Studies</div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Alters</div></div><div className="abEnd"><div className="box">Base saving throws, the key ability score of wild talents</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Passive Ability</div></div><div className="abEnd"><div className="box">A dark elementalist's base Will save bonus from the kineticist class is equal to 2 + 1/2 her kineticist level, and her base Reflex and Fortitude save bonuses are equal to <Link to="/misc/one_third">one-third</Link> of her kineticist level.</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Info</div></div><div className="abEnd"><div className="box">A dark elementalist uses her Intelligence modifier instead of her Constitution modifier to determine her damage with wild talents, the DCs of Constitution-based wild talents, the durations of wild talents with Constitution-based durations, her bonus on <Link to="/rule/concentration">concentration</Link> checks for wild talents, and any other Constitution-based effects of all her wild talents.</div></div></div></div>
<div className="ability p"><div className="abIcon"><Link to="/icons/armor-upgrade"><IonIcon icon="/icons/armor-upgrade.svg" color="secondary" /></Link><Link to="/icons/magic-swirl"><IonIcon icon="/icons/magic-swirl.svg" color="secondary" /></Link><Link to="/icons/upgrade"><IonIcon icon="/icons/upgrade.svg" color="secondary" /></Link><Link to="/icons/broken-shield"><IonIcon icon="/icons/broken-shield.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-kineticist-dark_elementalist-soul-power" data-hash-target><div className="box">Soul Power</div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Replaces</div></div><div className="abEnd"><div className="box">Internal buffer</div></div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Alters</div></div><div className="abEnd"><div className="box">Burn, elemental overflow</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Ability</div></div><div className="abEnd"><div className="box"><p>A dark elementalist uses the souls of others to protect herself from the dangers of burn. She can't choose to accept burn if doing so would raise her total number of points of burn above 3. However, a number of times per day equal to her Intelligence modifier, as a <strong className="hl">full-round action</strong> she can gather up the soul of a sentient creature with a CR equal to or higher than her character level, as long as that creature died in the past minute. When she does, some of her existing burn is unloaded into the departing soul, racking it with unspeakable torment, but reducing her current burn total by 1 point. A soul used in this way cannot be brought back to life as if it died of a death effect. Using a soul like this doesn't heal the nonlethal damage from that point of burn immediately, but does enable the dark elementalist to heal the nonlethal damage from that point of burn normally.</p>
<p>A dark elementalist gains attack and damage bonuses from <em>elemental overflow</em> based on how many times that day she has used <em>soul power</em> to rack a soul, rather than based on her current burn total. For instance, a 9th-level dark elementalist who used <em>soul power</em> to rack three or more souls during the course of the day would add a +3 bonus on attack rolls and a +6 bonus on damage rolls. A dark elementalist does not gain size bonuses to physical ability scores or a chance to ignore critical hits and sneak attacks from <em>elemental overflow.</em></p>
</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">At 6th Level</div></div><div className="abEnd"><div className="box">Racking a soul in this way forces anyone trying to bring the creature back to life to succeed at a caster level check (DC = 10 + the dark elementalist's kineticist level) or the attempt fails.</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">At 11th Level</div></div><div className="abEnd"><div className="box">Even if the creature returns from the dead, its racked soul is so damaged by the agony that it takes 2d6 points of <Link to="/rule/wisdom_damage">Wisdom damage</Link> (or 3d10 points of sanity damage if using the <Link to="/rule/sanity">sanity system</Link>).</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">At 16th Level</div></div><div className="abEnd"><div className="box">The racked soul is destroyed in the process, and the creature can be restored only by a <Link to="/spell/miracle">miracle</Link> or <Link to="/spell/wish">wish</Link>.</div></div></div></div>
</>};
const _elemental_annihilator = {title: "Elemental Annihilator", jsx: <><h2 id="arc-kineticist-elemental_annihilator-elemental-annihilator">Elemental Annihilator</h2>
<p><strong>Sources</strong> <Link to="/source/occult_adventures">Occult Adventures pg. 89</Link><br/>For some kineticists, nothing in life is as sweet as destruction and pain. Elemental annihilators pursue only uses of their powers that harm others.</p>
<div className="ability p"><div className="abIcon"><Link to="/icons/stairs-goal"><IonIcon icon="/icons/stairs-goal.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-kineticist-elemental_annihilator-devastating-infusion-su" data-hash-target><div className="box">Devastating Infusion (Su)</div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Alters</div></div><div className="abEnd"><div className="box">1st-level infusion, the basic utility wild talent normally granted by selecting an <Link to="/ability/elements">element</Link></div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Gained</div></div><div className="abEnd"><div className="box">At 1st Level</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Ability</div></div><div className="abEnd"><div className="box">An elemental annihilator can either shoot her kinetic blast at a target within 30 feet or make a single melee attack as if she were using <Link to="/kinetic/kinetic_blade">kinetic blade</Link> as an attack action. For this attack, the elemental annihilator's base attack bonus from her kineticist levels is equal to her full kineticist level. A <em>devastating infusion</em> always deals an amount of damage equal to 1d8 + the elemental annihilator's Constitution modifier, regardless of the annihilator's class level or use of composite blasts. When making a melee attack with <em>devastating infusion,</em> the elemental annihilator doesn't provoke attacks of opportunity, and if she uses two hands, the attack's damage is equal to 1d8 + 1-1/2 times her Constitution modifier. This is a 1st-level form infusion that costs 0 points of burn and can be used with any physical blast (but not energy blasts). Unlike with <em>kinetic blade,</em> the elemental annihilator can use <Link to="/feat/vital_strike">Vital Strike</Link> with <em>devastating infusion.</em> The damage bonus from <em>elemental overflow</em> doesn't apply to <em>devastating infusion's</em> damage rolls.</div></div></div></div>
<div className="ability p"><div className="abIcon"><Link to="/icons/broken-shield"><IonIcon icon="/icons/broken-shield.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-kineticist-elemental_annihilator-dampened-versatility-ex" data-hash-target><div className="box">Dampened Versatility (Ex)</div></div>
<div className="abPair"><div className="abStart"><div className="box">Info</div></div><div className="abEnd"><div className="box">An elemental annihilator can never gain utility wild talents.</div></div></div></div>
<div className="ability p"><div className="abIcon"><Link to="/icons/stairs-goal"><IonIcon icon="/icons/stairs-goal.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-kineticist-elemental_annihilator-bonus-feats" data-hash-target><div className="box">Bonus Feats</div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Replaces</div></div><div className="abEnd"><div className="box">2nd-, 8th-, 10th-, 14th-, and 18th-level utility wild talents</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Gained</div></div><div className="abEnd"><div className="box">At 2nd Level</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Ability</div></div><div className="abEnd"><div className="box">An elemental annihilator can select a bonus feat from the following list: <Link to="/feat/deadly_aim">Deadly Aim</Link>, <Link to="/feat/double_slice">Double Slice</Link>, <Link to="/feat/point_blank_shot">Point-Blank Shot</Link>, <Link to="/feat/power_attack">Power Attack</Link>, <Link to="/feat/precise_shot">Precise Shot</Link>, <Link to="/feat/rapid_shot">Rapid Shot</Link>, <Link to="/feat/two_weapon_fighting">Two-Weapon Fighting</Link>, <Link to="/feat/weapon_finesse">Weapon Finesse</Link>, and <Link to="/feat/weapon_focus">Weapon Focus</Link>. Rapid Shot and Two-Weapon Fighting can be used with a kinetic blast only if the annihilator also possesses <em>flurry of devastation</em> (see below).</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">At 8th Level</div></div><div className="abEnd"><div className="box">She gains an additional bonus feat. Her potential choices now include <Link to="/feat/improved_two_weapon_fighting">Improved Two-Weapon Fighting</Link> and <Link to="/feat/weapon_specialization">Weapon Specialization</Link>.</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">At 10th Level</div></div><div className="abEnd"><div className="box">She gains an additional bonus feat. She can also select from <Link to="/feat/greater_weapon_focus">Greater Weapon Focus</Link>, <Link to="/feat/improved_critical">Improved Critical</Link>, <Link to="/feat/improved_precise_shot">Improved Precise Shot</Link>, and <Link to="/feat/two_weapon_rend">Two-Weapon Rend</Link>.</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">At 14th Level</div></div><div className="abEnd"><div className="box">She gains an additional bonus feat.</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">At 18th Level</div></div><div className="abEnd"><div className="box">She gains an additional bonus feat.</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Special</div></div><div className="abEnd"><div className="box">An elemental annihilator doesn't need to meet the prerequisites for these feats to select them as bonus feats.</div></div></div></div>
<div className="ability p"><div className="abIcon"><Link to="/icons/stairs-goal"><IonIcon icon="/icons/stairs-goal.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-kineticist-elemental_annihilator-increased-range-su" data-hash-target><div className="box">Increased Range (Su)</div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Replaces</div></div><div className="abEnd"><div className="box">3rd- and 9th-level infusions</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">At 3rd Level</div></div><div className="abEnd"><div className="box">An elemental annihilator gains the <Link to="/kinetic/extended_range">extended range</Link> infusion.</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">At 9th Level</div></div><div className="abEnd"><div className="box">She gains the <Link to="/kinetic/extreme_range">extreme range</Link> infusion.</div></div></div></div>
<div className="ability p"><div className="abIcon"><Link to="/icons/mailed-fist"><IonIcon icon="/icons/mailed-fist.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-kineticist-elemental_annihilator-ever-present-threat-su" data-hash-target><div className="box">Ever-Present Threat (Su)</div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Replaces</div></div><div className="abEnd"><div className="box">4th-level utility wild talent</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Gained</div></div><div className="abEnd"><div className="box">At 4th Level</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Ability</div></div><div className="abEnd"><div className="box">An elemental annihilator threatens all foes within her natural reach. If anyone provokes an attack of opportunity from her, she can form her melee <em>devastating infusion</em> and make the attack, after which the weapon disappears.</div></div></div></div>
<div className="ability p"><div className="abIcon"><Link to="/icons/upgrade"><IonIcon icon="/icons/upgrade.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-kineticist-elemental_annihilator-blast-training-ex" data-hash-target><div className="box">Blast Training (Ex)</div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Replaces</div></div><div className="abEnd"><div className="box">5th-level infusion</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Gained</div></div><div className="abEnd"><div className="box">At 5th Level</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Passive Ability</div></div><div className="abEnd"><div className="box">An elemental annihilator gains a +1 bonus on attack rolls and damage rolls with her <em>devastating infusion</em> form infusion.</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">At 9th Level</div></div><div className="abEnd"><div className="box">This bonus becomes +2.</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">At 13th Level</div></div><div className="abEnd"><div className="box">This bonus increases to +3.</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">At 17th Level</div></div><div className="abEnd"><div className="box">This bonus becomes +4.</div></div></div></div>
<div className="ability p"><div className="abIcon"><Link to="/icons/stairs-goal"><IonIcon icon="/icons/stairs-goal.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-kineticist-elemental_annihilator-flurry-of-devastation-su" data-hash-target><div className="box">Flurry of Devastation (Su)</div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Replaces</div></div><div className="abEnd"><div className="box">6th-, 12th-, and 16th level utility wild talents</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Gained</div></div><div className="abEnd"><div className="box">At 6th Level</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Ability</div></div><div className="abEnd"><div className="box">An elemental annihilator can make a full attack of <em>devastating infusions</em> against targets within 120 feet as a full-attack action. Each individual attack deals damage as a <em>devastating infusion.</em> This is a 3rd-level form infusion that costs 1 point of burn and can be used with the same blast types as <em>devastating infusion.</em> Abilities such as Rapid Shot and <Link to="/spell/haste">haste</Link> that grant additional attacks apply normally to this full attack. If she makes only melee attacks with her <em>flurry of devastation,</em> she can use the Two-Weapon Fighting feats (unlike with the <em>kinetic blade</em> wild talent), but ranged <em>devastating infusions</em> do not work with Two-Weapon Fighting. For the elemental annihilator's off-hand attacks with Two-Weapon Fighting, she adds half her Constitution modifier to the damage (increasing to her full Constitution modifier if she has Double Slice). Though she can normally mix melee and ranged attacks with her <em>flurry of devastation,</em> she can't do so when she uses Two-Weapon Fighting. She can never use <em>metakinesis</em> or substance infusions with <em>flurry of devastation.</em></div></div></div></div>
<div className="ability p"><div className="abIcon"><Link to="/icons/stairs-goal"><IonIcon icon="/icons/stairs-goal.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-kineticist-elemental_annihilator-omnicide-su" data-hash-target><div className="box">Omnicide (Su)</div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Replaces</div></div><div className="abEnd"><div className="box">Omnikinesis, 20th-level utility wild talent</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Gained</div></div><div className="abEnd"><div className="box">At 20th Level</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Ability</div></div><div className="abEnd"><div className="box">An elemental annihilator can unleash <em>omnicide,</em> a unique physical composite blast. <em>Omnicide</em> deals 10d6+10 points of bludgeoning damage, 10d6+10 points of cold damage, 10d6+10 points of electricity damage, 10d6+10 points of fire damage, and 10d6+10 points of force damage, and counts as a blast of all five elements.<sup><InnerLink showBacklink="backlink-arc-kineticist-elemental_annihilator-fake-fn-1" id="arc-kineticist-elemental_annihilator-fake-fn-1" data-hash-target to="arc-kineticist-elemental_annihilator-fake-fn-1-target">1</InnerLink></sup> <em>Omnicide</em> costs 4 points of burn, which can be reduced by <em>composite specialization</em> as normal.</div></div></div></div>
<section data-footnotes><h3 id="arc-kineticist-elemental_annihilator-label">Footnotes</h3><ol>
<li id="arc-kineticist-elemental_annihilator-fake-fn-1-target"><p>This archetype was published before the void and wood elements were created. consult your GM if you want to master those elements, too. <InnerLink aria-label="Back to reference 1" id="backlink-arc-kineticist-elemental_annihilator-fake-fn-1" data-hash-target to="arc-kineticist-elemental_annihilator-fake-fn-1">↩</InnerLink></p></li>
</ol></section></>};
const _elemental_ascetic = {title: "Elemental Ascetic", jsx: <><h2 id="arc-kineticist-elemental_ascetic-elemental-ascetic">Elemental Ascetic</h2>
<p><strong>Sources</strong> <Link to="/source/occult_adventures">Occult Adventures pg. 90</Link><br/>Combining the elemental powers of a kineticist with the rigid physical discipline of a monk, an elemental ascetic channels his powers through his body to enhance himself in combat.</p>
<div className="ability p"><div className="abIcon"><Link to="/icons/stairs-goal"><IonIcon icon="/icons/stairs-goal.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-kineticist-elemental_ascetic-elemental-flurry-su" data-hash-target><div className="box">Elemental Flurry (Su)</div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Replaces</div></div><div className="abEnd"><div className="box">Elemental overflow</div></div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Alters</div></div><div className="abEnd"><div className="box">Kinetic blast</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Gained</div></div><div className="abEnd"><div className="box">At 1st Level</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Ability</div></div><div className="abEnd"><div className="box">An elemental ascetic gains <Link to="/feat/improved_unarmed_strike">Improved Unarmed Strike</Link> as a bonus feat. He gains the <Link to="/kinetic/kinetic_fist">kinetic fist</Link> form infusion and it costs 0 points of burn instead of 1 point of burn. When using the <em>kinetic fist</em> form infusion with a full attack, he can make a <em>flurry of blows</em> as the <Link to="/class/monk">monk</Link> class feature. He must use only his fists to make this flurry, no matter what other abilities he possesses. Like a monk, he can use this ability only when unarmored, not using a shield, and unencumbered. He can't use his kinetic blast without a form infusion, nor can he ever use his kinetic blast with the <Link to="/kinetic/chain">chain</Link>, <Link to="/kinetic/extended_range">extended range</Link>, <Link to="/kinetic/extreme_range">extreme range</Link>, <Link to="/kinetic/foe_throw">foe throw</Link>, <Link to="/kinetic/flurry_of_blasts">flurry of blasts</Link>, <Link to="/kinetic/many_throw">many throw</Link>, or <Link to="/kinetic/snake">snake</Link> form infusions, or with any other form infusion that requires a ranged attack roll or ranged touch attack roll.</div></div></div></div>
<div className="ability p"><div className="abIcon"><Link to="/icons/info"><IonIcon icon="/icons/info.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-kineticist-elemental_ascetic-elemental-wisdom-su" data-hash-target><div className="box">Elemental Wisdom (Su)</div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Alters</div></div><div className="abEnd"><div className="box">Key ability scores of wild talents</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Choice</div></div><div className="abEnd"><div className="box">An elemental ascetic can use his Wisdom modifier instead of his Constitution modifier to determine the DCs of Constitution-based wild talents, the duration of wild talents with a Constitution-based duration, and his bonus on <Link to="/rule/concentration">concentration</Link> checks for wild talents.</div></div></div></div>
<div className="ability p"><div className="abIcon"><Link to="/icons/armor-upgrade"><IonIcon icon="/icons/armor-upgrade.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-kineticist-elemental_ascetic-ac-bonus-ex" data-hash-target><div className="box">AC Bonus (Ex)</div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Replaces</div></div><div className="abEnd"><div className="box">Elemental defense</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Gained</div></div><div className="abEnd"><div className="box">At 2nd Level</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Passive Ability</div></div><div className="abEnd"><div className="box">When unarmored, not using a shield, and unencumbered, an elemental ascetic adds his Wisdom bonus (if any) to his AC and his CMD. These bonuses to AC apply even against touch attacks or when the elemental ascetic is <Link to="/rule/flat_footed">flat-footed</Link>. He loses these bonuses when he is immobilized or helpless.</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Special</div></div><div className="abEnd"><div className="box">This bonus increases by 1 for every 4 kineticist levels the elemental ascetic possesses beyond 2nd. The elemental ascetic's kineticist levels stack with monk levels for the purpose of determining when the bonus increases. An elemental ascetic can never take the <Link to="/kinetic/expanded_defense">expanded defense</Link> utility wild talent.</div></div></div></div>
<div className="ability p"><div className="abIcon"><Link to="/icons/upgrade"><IonIcon icon="/icons/upgrade.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-kineticist-elemental_ascetic-powerful-fist-su" data-hash-target><div className="box">Powerful Fist (Su)</div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Replaces</div></div><div className="abEnd"><div className="box">5th-, 9th-, and 13th-level infusions</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">At 5th Level</div></div><div className="abEnd"><div className="box">An elemental ascetic can accept 2 additional points of burn when using <em>kinetic fist</em> to increase that infusion's damage dice from d6s to d8s.</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">At 9th Level</div></div><div className="abEnd"><div className="box">He can instead accept 3 additional points of burn to increase the damage dice from d6s to d10s.</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">At 13th Level</div></div><div className="abEnd"><div className="box">He can instead accept 4 additional points of burn to increase the damage dice from d6s to d12s.</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Special</div></div><div className="abEnd"><div className="box">All of these options count as burn from a form infusion and can thus be reduced by <em>infusion specialization.</em></div></div></div></div>
</>};
const _elemental_purist = {title: "Elemental Purist", jsx: <><h2 id="arc-kineticist-elemental_purist-elemental-purist">Elemental Purist</h2>
<p><strong>Sources</strong> <Link to="/source/planes_of_power">Planes of Power pg. 7</Link><br/>An elemental purist spurns all elements that are not her own, for utter devotion can allow one to accomplish even seemingly impossible heroics.</p>
<div className="ability p"><div className="abIcon"><Link to="/icons/broken-shield"><IonIcon icon="/icons/broken-shield.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-kineticist-elemental_purist-limited-buffer-su" data-hash-target><div className="box">Limited Buffer (Su)</div></div>
<div className="abPair"><div className="abStart"><div className="box">Info</div></div><div className="abEnd"><div className="box">An elemental purist does not gain <em>internal buffer</em> at 6th level. She instead gains <em>internal buffer</em> at 11th level and treats her kineticist level as 5 lower for the purpose of the ability.</div></div></div></div>
<div className="ability p"><div className="abIcon"><Link to="/icons/stairs-goal"><IonIcon icon="/icons/stairs-goal.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-kineticist-elemental_purist-elemental-impossibility-su" data-hash-target><div className="box">Elemental Impossibility (Su)</div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Replaces</div></div><div className="abEnd"><div className="box">Expanded element, 11th- and 19th-level infusions</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Gained</div></div><div className="abEnd"><div className="box">At 7th Level</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Ability</div></div><div className="abEnd"><div className="box">An elemental purist learns one composite blast as if she had an <em>expanded element</em> that matched her primary <Link to="/ability/elements">element</Link>. In addition, she learns one "impossible infusion" - a form infusion or substance infusion that does not need to be associated with her primary element's type. If the infusion can be applied to her kinetic blasts normally, she can use it as normal. If the infusion is not an associated infusion, she can accept 1 point of burn as a <strong className="hl">free action</strong> to enter a state of <em>elemental impossibility</em> for one minute. This burn cannot be reduced in any way. While in this state, she can apply her <em>impossible infusions</em> to her kinetic blast, even if it is not an associated infusion for the blast type; however, if an infusion can be applied only to energy blasts or only to physical blasts, she can apply it only to a kinetic blast of that type.</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">At 11th Level</div></div><div className="abEnd"><div className="box">The elemental purist learns one additional <em>impossible infusion.</em></div></div></div>
<div className="abPair"><div className="abStart"><div className="box">At 15th Level</div></div><div className="abEnd"><div className="box">The elemental purist learns one additional <em>impossible infusion.</em></div></div></div>
<div className="abPair"><div className="abStart"><div className="box">At 19th Level</div></div><div className="abEnd"><div className="box">The elemental purist learns one additional <em>impossible infusion.</em></div></div></div></div>
<div className="ability p"><div className="abIcon"><Link to="/icons/stairs-goal"><IonIcon icon="/icons/stairs-goal.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-kineticist-elemental_purist-elemental-apocalypse-su" data-hash-target><div className="box">Elemental Apocalypse (Su)</div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Replaces</div></div><div className="abEnd"><div className="box">Omnikinesis</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Gained</div></div><div className="abEnd"><div className="box">At 20th Level</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Ability</div></div><div className="abEnd"><div className="box">An elemental purist learns the <em>apocalypse</em> universal form infusion (<strong>Level</strong> 9; <strong>Burn</strong> 5; <strong>Associated Blasts</strong> any; <strong>Saving Throw</strong> Reflex half) that she can use once per day. The <em>apocalypse</em> form infusion functions as the <Link to="/kinetic/explosion">explosion</Link> form infusion, except the elemental purist can center the spread anywhere she can see within 1 mile, and she can choose to set the radius anywhere between 5 feet and 360 feet.</div></div></div></div>
</>};
const _elysiokineticist = {title: "Elysiokineticist", jsx: <><h2 id="arc-kineticist-elysiokineticist-elysiokineticist">Elysiokineticist</h2>
<p><strong>Sources</strong> <Link to="/source/people_of_the_wastes">People of the Wastes pg. 18</Link><br/>Similar to how phytokineticists draw their power from the First World, elysiokineticists trace their abilities to the riotous wilderness of the plane known as Elysium. Many such kineticists vow to fight against evil planar intrusions into the Material Plane, particularly the Worldwound.</p>
<div className="sideNoteWrap startAlign singular delist"><ScrollContainer id="arc-kineticist-elysiokineticist--table-0"><table><tbody><tr><ThLink scope="row" to="/icons/confirmed"><IonIcon aria-label="Prerequisites" icon="/icons/confirmed.svg" /></ThLink><td>Must be chaotic good</td></tr></tbody></table></ScrollContainer></div><div className="ability p"><div className="abIcon"><Link to="/icons/abstract-091"><IonIcon icon="/icons/abstract-091.svg" color="secondary" /></Link><Link to="/icons/info"><IonIcon icon="/icons/info.svg" color="secondary" /></Link><Link to="/icons/hazard-sign"><IonIcon icon="/icons/hazard-sign.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-kineticist-elysiokineticist-elysiums-soul" data-hash-target><div className="box">Elysium's Soul</div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Replaces</div></div><div className="abEnd"><div className="box">Expanded element</div></div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Alters</div></div><div className="abEnd"><div className="box">Elemental focus</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Passive Ability</div></div><div className="abEnd"><div className="box">An elysiokineticist has alignment auras of chaotic and good as if she were a chaotic good <Link to="/type/outsider">outsider</Link> with a number of Hit Dice equal to her kineticist level.</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Info</div></div><div className="abEnd"><div className="box">She must choose wood as her primary <Link to="/ability/elements">element</Link> and <Link to="/kinetic/positive_blast">positive blast</Link> as her first simple blast.</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">At 7th Level</div></div><div className="abEnd"><div className="box">She gains <Link to="/kinetic/verdant_blast">verdant blast</Link> and <Link to="/kinetic/wood_blast">wood blast</Link>, as well as a 3rd-level or lower wild talent of her choice.</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">At 15th Level</div></div><div className="abEnd"><div className="box">She gains a 7th-level wild talent of her choice.</div></div></div></div>
<div className="ability p"><div className="abIcon"><Link to="/icons/skills"><IonIcon icon="/icons/skills.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-kineticist-elysiokineticist-undefined" data-hash-target><div className="box">Class Skills</div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Alters</div></div><div className="abEnd"><div className="box">Class skills</div></div></div><div className="abPair"><div className="abStart"><div className="box">New Class Skills</div></div><div className="abEnd"><div className="box"><Link to="/skill/heal">Heal</Link> (WIS), <Link to="/skill/knowledge_religion">Knowledge (religion)</Link> (INT)</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Removed Skills</div></div><div className="abEnd"><div className="box">Handle Animal, Knowledge (nature)</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Info</div></div><div className="abEnd"><div className="box">These replacements alter the class skills granted by the wood element.</div></div></div></div>
<div className="ability p"><div className="abIcon"><Link to="/icons/magic-swirl"><IonIcon icon="/icons/magic-swirl.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-kineticist-elysiokineticist-basic-elysiokinesis-sp" data-hash-target><div className="box">Basic Elysiokinesis (Sp)</div><div className="flavor">An elysiokineticist can use the power of Elysium to assist others and bolster their vigor.</div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Replaces</div></div><div className="abEnd"><div className="box">Basic phytokinesis utility wild talent granted by the wood element</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Standard Action</div></div><div className="abEnd"><div className="box">She can cast <Link to="/spell/resistance">resistance</Link>, <Link to="/spell/stabilize">stabilize</Link>, or <Link to="/spell/virtue">virtue</Link> as a spell-like ability at will.</div></div></div></div>
<div className="ability p"><div className="abIcon"><Link to="/icons/upgrade"><IonIcon icon="/icons/upgrade.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-kineticist-elysiokineticist-elysian-infusion-su" data-hash-target><div className="box">Elysian Infusion (Su)</div><div className="flavor">An elysiokineticist can infuse her <em>positive blast</em> with the power of Elysium to battle evil.</div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Replaces</div></div><div className="abEnd"><div className="box">Infusion gained at 1st level</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Ability</div></div><div className="abEnd"><div className="box">The infused <em>positive blast</em> damages evil outsiders as if they were undead and counts as both chaotic and good. This is a 1st-level substance infusion that costs 1 point of burn and can be used with <em>positive blast.</em></div></div></div></div>
<div className="ability p"><div className="abIcon"><Link to="/icons/armor-upgrade"><IonIcon icon="/icons/armor-upgrade.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-kineticist-elysiokineticist-elysian-aura-su" data-hash-target><div className="box">Elysian Aura (Su)</div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Replaces</div></div><div className="abEnd"><div className="box"><em>Flesh of wood</em> defense wild talent granted by the wood element</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Gained</div></div><div className="abEnd"><div className="box">At 2nd Level</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Passive Ability</div></div><div className="abEnd"><div className="box">An elysiokineticist infuses herself with a holy aura, granting her protection against evil attacks. She gains a +1 deflection bonus to AC and a +1 resistance bonus on saving throws; both apply only against attacks from evil creatures. By accepting 1 point of burn, she can increase both bonuses by 1.</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">At 5th Level</div></div><div className="abEnd"><div className="box">She can instead accept 2 points of burn to increase both bonuses by 2.</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">At 8th Level</div></div><div className="abEnd"><div className="box">She can instead accept 3 points of burn to increase both bonuses by 3.</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">At 11th Level</div></div><div className="abEnd"><div className="box">She can instead accept 4 points of burn to increase both bonuses by 4.</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">At 14th Level</div></div><div className="abEnd"><div className="box">She can instead accept 5 points of burn to increase both bonuses by 5.</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">At 17th Level</div></div><div className="abEnd"><div className="box">She can instead accept 6 points of burn to increase both bonuses by 6.</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Special</div></div><div className="abEnd"><div className="box">Whenever she accepts burn while using a wood wild talent, the energy causes her <em>elysian aura</em> bonuses to apply against all attacks for 1 round, and during that time she is protected from evil mental and possession effects, as per <Link to="/spell/protection_from_evil">protection from evil</Link>. She can dismiss or restore this effect as an <strong className="hl">immediate action</strong>.</div></div></div></div>
<div className="ability p"><div className="abIcon"><Link to="/icons/stairs-goal"><IonIcon icon="/icons/stairs-goal.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-kineticist-elysiokineticist-ghaelelight-blast-su" data-hash-target><div className="box">Ghaelelight Blast (Su)</div></div>
<div className="abPair"><div className="abStart"><div className="box">Gained</div></div><div className="abEnd"><div className="box">At 15th Level</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Ability</div></div><div className="abEnd"><div className="box">An elysiokineticist gains the <em>ghaelelight composite blast,</em> which costs 2 points of burn. A <em>ghaelelight blast</em> is an energy blast that deals damage as a simple energy blast instead of a composite energy blast and deals chaotic and good damage. It is associated with the same infusions as <em>positive blast.</em></div></div></div></div>
</>};
const _ioun_kineticist = {title: "Ioun Kineticist", jsx: <><h2 id="arc-kineticist-ioun_kineticist-ioun-kineticist">Ioun Kineticist</h2>
<p><strong>Sources</strong> <Link to="/source/blood_of_the_ancients">Blood of the Ancients pg. 12</Link><br/>Among the greatest technologies to come from Azlant are ioun stones, small crystalline minerals imbued with magical energies that modern scholars still struggle to dissect. Some kineticists dedicate themselves to unlocking ioun stones' cosmic secrets and seemingly limitless potential.</p>
<div className="ability p"><div className="abIcon"><Link to="/icons/info"><IonIcon icon="/icons/info.svg" color="secondary" /></Link><Link to="/icons/broken-shield"><IonIcon icon="/icons/broken-shield.svg" color="secondary" /></Link><Link to="/icons/stairs-goal"><IonIcon icon="/icons/stairs-goal.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-kineticist-ioun_kineticist-ioun-focus" data-hash-target><div className="box">Ioun Focus</div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Alters</div></div><div className="abEnd"><div className="box">Elemental focus</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Info</div></div><div className="abEnd"><div className="box">An ioun kineticist must choose aether as her <Link to="/ability/elements">elemental focus</Link>. She cannot select <Link to="/kinetic/disintegrating_infusion">disintegrating infusion</Link>, <Link to="/kinetic/foe_throw">foe throw</Link>, or <Link to="/kinetic/force_hook">force hook</Link> as infusions, nor can she select <Link to="/kinetic/aether_puppet">aether puppet</Link>, <Link to="/kinetic/telekinetic_finesse">telekinetic finesse</Link>, <Link to="/kinetic/telekinetic_haul">telekinetic haul</Link>, or <Link to="/kinetic/telekinetic_invisibility">telekinetic invisibility</Link> as wild talents. She instead treats the following infusions and wild talents as though they were part of the aether element: <Link to="/kinetic/cyclone">cyclone</Link>, <Link to="/kinetic/fragmentation">fragmentation</Link>, <Link to="/kinetic/jagged_flesh">jagged flesh</Link>, and <Link to="/kinetic/rare_metal_infusion">rare-metal infusion</Link>. These infusions can be applied to the ioun kineticist's <Link to="/kinetic/telekinetic_blast">telekinetic blast</Link> and <em>Azlanti composite blast</em> (see below).</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Special</div></div><div className="abEnd"><div className="box">An ioun kineticist's telekinetic blast always sends one or more of her ioun stones to strike her foes and immediately return, and her wild talents typically manifest as her ioun stones moving or spinning to create fields of energy.</div></div></div></div>
<div className="ability p"><div className="abIcon"><Link to="/icons/stairs-goal"><IonIcon icon="/icons/stairs-goal.svg" color="secondary" /></Link><Link to="/icons/shield-reflect"><IonIcon icon="/icons/shield-reflect.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-kineticist-ioun_kineticist-ioun-cloud-su" data-hash-target><div className="box">Ioun Cloud (Su)</div></div>
<div className="abPair"><div className="abStart"><div className="box">Ability</div></div><div className="abEnd"><div className="box">An ioun kineticist forms a powerful bond with three <Link to="/magic-ioun/dull_gray">dull gray ioun stones</Link>, referred to as her <em>ioun cloud.</em> She begins play with these stones at no cost. She also increases the AC of stones in her <em>ioun cloud</em> by an amount equal to her class level, and she increases the hardness of these stones by an amount equal to half her class level (minimum +0). An ioun kineticist cannot use her <em>gather power, ioun buffer, kinetic blast,</em> or <em>personal resonance</em> class abilities unless she has at least one bonded ioun stone orbiting her. She takes a cumulative -2 penalty on <Link to="/rule/concentration">concentration</Link> checks for each bonded ioun stone less than her possible maximum in her current <em>ioun cloud.</em> When she uses her <em>gather power</em> class ability, her <em>ioun cloud</em> buzzes, glows, spins rapidly, and traces eldritch symbols in the air.</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">At 6th Level</div></div><div className="abEnd"><div className="box">She gains a bond with a 4th free dull gray ioun.</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">At 12th Level</div></div><div className="abEnd"><div className="box">She gains a bond with a 5th free dull gray ioun.</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">At 18th Level</div></div><div className="abEnd"><div className="box">She gains a bond with a 6th free dull gray ioun.</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Special</div></div><div className="abEnd"><div className="box">While the ioun kineticist can own additional ioun stones outside of this bond, only bonded ioun stones can be a part of her <em>ioun cloud.</em> An ioun kineticist can spend 1 hour meditating with an ioun stone to bond with it and add it to her <em>ioun cloud,</em> but doing so immediately unbonds and removes one ioun stone of her choice from her <em>ioun cloud</em> unless she is replacing an ioun stone that has been lost or destroyed.</div></div></div></div>
<div className="ability p"><div className="abIcon"><Link to="/icons/magic-swirl"><IonIcon icon="/icons/magic-swirl.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-kineticist-ioun_kineticist-basic-iounkinesis-su-or-sp" data-hash-target><div className="box">Basic Iounkinesis (Su or Sp)</div><div className="flavor">An ioun kineticist can manipulate ioun stones with ease and channel their magical fields to create simple effects.</div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Alters</div></div><div className="abEnd"><div className="box"><Link to="/kinetic/basic_telekinesis">Basic telekinesis</Link> utility wild talent granted by the aether element</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Ability</div></div><div className="abEnd"><div className="box">She can activate (making the stones orbit her) or stow a number of ioun stones equal to her class level in any combination as a <strong className="hl">move action</strong>, and she can activate or stow twice as many as a <strong className="hl">standard action</strong>. She can affect only ioun stones orbiting her and unattended ioun stones within 15 feet with this ability. This ability also allows her to cast <Link to="/spell/prestidigitation">prestidigitation</Link> at will as a spell-like ability.</div></div></div></div>
<div className="ability p"><div className="abIcon"><Link to="/icons/magic-swirl"><IonIcon icon="/icons/magic-swirl.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-kineticist-ioun_kineticist-ioun-buffer-su" data-hash-target><div className="box">Ioun Buffer (Su)</div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Alters</div></div><div className="abEnd"><div className="box">Internal buffer</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Ability</div></div><div className="abEnd"><div className="box">An ioun kineticist can store excess energy in her <em>ioun cloud.</em> This functions as the kineticist's <em>internal buffer</em> ability, except she stores each point of burn within a different ioun stone in her <em>ioun cloud.</em> She can access the burn stored in an ioun stone only if it is orbiting her. When expending an ioun stone's stored point of burn to reduce the cost of a blast wild talent, the ioun kineticist can expend all of that ioun stone's energy, permanently transforming it into a dull gray ioun stone. If the ioun stone's market price was at least 4,000 gp, this effect further reduces the burn cost of that wild talent by 2. If the ioun stone's market price was at least 10,000 gp, it instead further reduces the burn cost by 3. If the ioun stone's market price was more than 20,000 gp, it instead further reduces the burn cost by 4.</div></div></div></div>
<div className="ability p"><div className="abIcon"><Link to="/icons/magic-swirl"><IonIcon icon="/icons/magic-swirl.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-kineticist-ioun_kineticist-personal-resonance-su" data-hash-target><div className="box">Personal Resonance (Su)</div><div className="flavor">An ioun kineticist can harmonize her body's energies with that of her ioun cloud.</div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Replaces</div></div><div className="abEnd"><div className="box">The ability score boosts granted by <em>elemental overflow</em></div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Gained</div></div><div className="abEnd"><div className="box">At 6th Level</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Ability</div></div><div className="abEnd"><div className="box">Whenever she has at least 3 points of burn, she gains the resonant powers of two ioun stones of her choice in her <em>ioun cloud;</em> she is treated as holding a <Link to="/magic-wondrous/wayfinder">wayfinder</Link> for the purpose of using any resonant powers. As a <strong className="hl">standard action</strong>, she can switch which two ioun stones are granting their resonance powers.</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Choice</div></div><div className="abEnd"><div className="box">In place of gaining the resonant power of a <Link to="/magic-ioun/deep_red_sphere">deep red sphere</Link>, <Link to="/magic-ioun/incandescent_blue_sphere">incandescent blue sphere</Link>, <Link to="/magic-ioun/pale_blue_rhomboid">pale blue rhomboid</Link>, <Link to="/magic-ioun/pink_and_green_sphere">pink and green sphere</Link>, <Link to="/magic-ioun/pink_rhomboid">pink rhomboid</Link>, or <Link to="/magic-ioun/scarlet_and_blue_sphere">scarlet and blue sphere</Link>, the ioun kineticist can instead increase the enhancement bonus it grants to an ability score to +4. An ioun kineticist can increase only one ioun stone's enhancement bonus in this way at a time.</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">At 11th Level</div></div><div className="abEnd"><div className="box">Whenever she has at least 5 points of burn, she can gain the resonance powers of up to four ioun stones in her <em>ioun cloud,</em> and the bonus she can get from certain ioun stones becomes +5.</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">At 16th Level</div></div><div className="abEnd"><div className="box">Whenever she has at least 7 points of burn, she gains the resonance powers of all of the ioun stones in her <em>ioun cloud,</em> and the bonus she can get from certain ioun stones becomes +6.</div></div></div></div>
<div className="ability p"><div className="abIcon"><Link to="/icons/stairs-goal"><IonIcon icon="/icons/stairs-goal.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-kineticist-ioun_kineticist-azlanti-blast-su" data-hash-target><div className="box">Azlanti Blast (Su)</div></div>
<div className="abPair"><div className="abStart"><div className="box">Ability</div></div><div className="abEnd"><div className="box">An ioun kineticist who selects aether as her <em>expanded element</em> does not gain the <Link to="/kinetic/force_blast">force composite blast</Link>. She instead gains the <em>Azlanti composite blast,</em> which costs 2 points of burn. An <em>Azlanti blast</em> is a physical blast that deals bludgeoning, piercing, or slashing damage.</div></div></div></div>
</>};
const _kinetic_chirurgeon = {title: "Kinetic Chirurgeon", jsx: <><h2 id="arc-kineticist-kinetic_chirurgeon-kinetic-chirurgeon">Kinetic Chirurgeon</h2>
<p><strong>Sources</strong> <Link to="/source/occult_adventures">Occult Adventures pg. 90</Link><br/>While any hydrokineticist or telekineticist can learn the rudiments of healing, some kineticists are virtuosos of the curative arts.</p>
<div className="ability p"><div className="abIcon"><Link to="/icons/info"><IonIcon icon="/icons/info.svg" color="secondary" /></Link><Link to="/icons/stairs-goal"><IonIcon icon="/icons/stairs-goal.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-kineticist-kinetic_chirurgeon-kinetic-chirurgery-su" data-hash-target><div className="box">Kinetic Chirurgery (Su)</div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Replaces</div></div><div className="abEnd"><div className="box">Infusions</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Ability</div></div><div className="abEnd"><div className="box">A kinetic chirurgeon must select either aether or water as her primary <Link to="/ability/elements">element</Link>. She gains <Link to="/kinetic/kinetic_healer">kinetic healer</Link> as a bonus wild talent at 1st level.</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">At 3rd Level</div></div><div className="abEnd"><div className="box">The kinetic chirurgeon can select any one <Link to="/class/paladin">paladin</Link> <Link to="/ability/mercy">mercy</Link> that a paladin of that level could select. Each time she uses <em>kinetic healer,</em> she can apply this mercy to the target of the healing.</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">At 5th Level</div></div><div className="abEnd"><div className="box">She can select a 3rd mercy (of an appropriate level). She can apply only one of her chosen mercies when she uses <em>kinetic healer.</em></div></div></div>
<div className="abPair"><div className="abStart"><div className="box">At 7th Level</div></div><div className="abEnd"><div className="box">She can pick a 4th mercy (of an appropriate level).</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">At 9th Level</div></div><div className="abEnd"><div className="box">She can choose a 5th mercy (of an appropriate level).</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">At 11th Level</div></div><div className="abEnd"><div className="box">She can select a 6th mercy (of an appropriate level).</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">At 13th Level</div></div><div className="abEnd"><div className="box">She can pick a 7th mercy (of an appropriate level).</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">At 15th Level</div></div><div className="abEnd"><div className="box">She can choose a 8th mercy (of an appropriate level).</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">At 17th Level</div></div><div className="abEnd"><div className="box">She can select a 9th mercy (of an appropriate level).</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">At 19th Level</div></div><div className="abEnd"><div className="box">She can pick a 10th mercy (of an appropriate level).</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Special</div></div><div className="abEnd"><div className="box">A kinetic chirurgeon can never use infusions.</div></div></div></div>
<div className="ability p"><div className="abIcon"><Link to="/icons/stairs-goal"><IonIcon icon="/icons/stairs-goal.svg" color="secondary" /></Link><Link to="/icons/upgrade"><IonIcon icon="/icons/upgrade.svg" color="secondary" /></Link><Link to="/icons/heart-plus"><IonIcon icon="/icons/heart-plus.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-kineticist-kinetic_chirurgeon-metahealer-su" data-hash-target><div className="box">Metahealer (Su)</div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Replaces</div></div><div className="abEnd"><div className="box">Metakinesis, infusion specialization</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Gained</div></div><div className="abEnd"><div className="box">At 5th Level</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Ability</div></div><div className="abEnd"><div className="box">A kinetic chirurgeon can apply any one of the following <em>metahealer</em> abilities to her <em>kinetic healer</em> wild talent instead of using her mercies.</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">At 5th Level</div></div><div className="abEnd"><div className="box">She can choose to roll one additional die when using <em>kinetic healer.</em></div></div></div>
<div className="abPair"><div className="abStart"><div className="box">At 9th Level</div></div><div className="abEnd"><div className="box">She can choose to bring an ally who died within 1 round back from the dead; this functions similarly to the <Link to="/spell/breath_of_life">breath of life</Link> spell. The ally regains the normal number of hit points from <em>kinetic healer.</em> An ally revived in this way takes 1 additional point of burn, beyond the normal 1 point of burn that either the kinetic chirurgeon or the ally must accept as a cost of the <em>kinetic healer</em> wild talent.</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">At 11th Level</div></div><div className="abEnd"><div className="box">She can choose to roll two additional dice when using <em>kinetic healer.</em></div></div></div>
<div className="abPair"><div className="abStart"><div className="box">At 13th Level</div></div><div className="abEnd"><div className="box">A kinetic chirurgeon can choose to use <em>kinetic healer</em> on herself as a <strong className="hl">swift action</strong>.</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">At 17th Level</div></div><div className="abEnd"><div className="box">She can choose to roll three additional dice when using <em>kinetic healer.</em> Or, she can choose to heal both herself and another target with the same use of <em>kinetic healer,</em> although in that case, both she and her target must each accept 1 point of burn, instead of only one of them needing to do so as normal for <em>kinetic healer.</em></div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Special</div></div><div className="abEnd"><div className="box">Regardless of her level, the kinetic chirurgeon can apply only one <em>metahealer</em> ability to a single use of <em>kinetic healer.</em> For instance, she could not bring back a dead ally and also roll extra dice for healing.</div></div></div></div>
<div className="ability p"><div className="abIcon"><Link to="/icons/upgrade"><IonIcon icon="/icons/upgrade.svg" color="secondary" /></Link><Link to="/icons/broken-shield"><IonIcon icon="/icons/broken-shield.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-kineticist-kinetic_chirurgeon-healing-buffer-su" data-hash-target><div className="box">Healing Buffer (Su)</div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Alters</div></div><div className="abEnd"><div className="box">Internal buffer</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Gained</div></div><div className="abEnd"><div className="box">At 6th Level</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Ability</div></div><div className="abEnd"><div className="box">A kinetic chirurgeon's <em>internal buffer</em> has double the usual maximum size, and she can use it only when she would accept points of burn for the <em>kinetic healer</em> wild talent.</div></div></div></div>
</>};
const _kinetic_knight = {title: "Kinetic Knight", jsx: <><h2 id="arc-kineticist-kinetic_knight-kinetic-knight">Kinetic Knight</h2>
<p><strong>Sources</strong> <Link to="/source/psychic_anthology">Psychic Anthology pg. 25</Link><br/>A kinetic knight dons armor and wields a blade of elemental energy. The Phoenix Kindred counted many of these resolute warriors among their number, combining the Recursion Tablets' secrets with a warrior's ways. Today, most remaining Tian kinetic knights follow the philosophy of ichimeiyo. Kinetic knights are rarer in the Inner Sea region, but not unknown; many realize their elemental powers while training for battle.</p>
<div className="ability p"><div className="abIcon"><Link to="/icons/skills"><IonIcon icon="/icons/skills.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-kineticist-kinetic_knight-undefined" data-hash-target><div className="box">Courtly</div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Alters</div></div><div className="abEnd"><div className="box">Class skills</div></div></div><div className="abPair"><div className="abStart"><div className="box">New Class Skills</div></div><div className="abEnd"><div className="box"><Link to="/skill/diplomacy">Diplomacy</Link> (CHA), <Link to="/skill/sense_motive">Sense Motive</Link> (WIS)</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Removed Skills</div></div><div className="abEnd"><div className="box">Acrobatics, Stealth</div></div></div></div>
<div className="ability p"><div className="abIcon"><Link to="/icons/stairs-goal"><IonIcon icon="/icons/stairs-goal.svg" color="secondary" /></Link><Link to="/icons/upgrade"><IonIcon icon="/icons/upgrade.svg" color="secondary" /></Link><Link to="/icons/broken-shield"><IonIcon icon="/icons/broken-shield.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-kineticist-kinetic_knight-elemental-blade-su" data-hash-target><div className="box">Elemental Blade (Su)</div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Replaces</div></div><div className="abEnd"><div className="box">Metakinesis, metakinetic master</div></div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Alters</div></div><div className="abEnd"><div className="box">Kinetic blast, infusions</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Gained</div></div><div className="abEnd"><div className="box">At 1st Level</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Ability</div></div><div className="abEnd"><div className="box">A kinetic knight gains the <Link to="/kinetic/kinetic_blade">kinetic blade</Link> form infusion, and it costs 0 points of burn instead of 1 point. She can't use her kinetic blast without the <em>kinetic blade</em> form infusion or an infusion that lists <em>kinetic blade</em> as a prerequisite.</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">At 3rd Level</div></div><div className="abEnd"><div className="box">The kinetic knight gains the <Link to="/kinetic/blade_rush">blade rush</Link> infusion.</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">At 5th Level</div></div><div className="abEnd"><div className="box">She gains the <Link to="/kinetic/kinetic_whip">kinetic whip</Link> infusion. Her kinetic whip has the <Link to="/misc/disarm">disarm</Link>, <Link to="/misc/performance">performance</Link>, and <Link to="/misc/trip">trip</Link> weapon qualities.</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">At 9th Level</div></div><div className="abEnd"><div className="box">She gains the <Link to="/kinetic/blade_whirlwind">blade whirlwind</Link> infusion.</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">At 11th Level</div></div><div className="abEnd"><div className="box">She gains the <Link to="/kinetic/whip_hurricane">whip hurricane</Link> infusion.</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">At 13th Level</div></div><div className="abEnd"><div className="box">As a <strong className="hl">swift action</strong>, she can accept 2 points of burn to unleash a kinetic blast with the <em>blade rush</em> infusion.</div></div></div></div>
<div className="ability p"><div className="abIcon"><Link to="/icons/upgrade"><IonIcon icon="/icons/upgrade.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-kineticist-kinetic_knight-kinetic-warrior-ex" data-hash-target><div className="box">Kinetic Warrior (Ex)</div></div>
<div className="abPair"><div className="abStart"><div className="box">Ability</div></div><div className="abEnd"><div className="box">The kinetic knight can use her Constitution score in place of her Intelligence score when qualifying for <Link to="/main/combat_feat">combat feats</Link>. This ability counts as having <Link to="/feat/combat_expertise">Combat Expertise</Link> for the purpose of feat prerequisites.</div></div></div></div>
<div className="ability p"><div className="abIcon"><Link to="/icons/stairs-goal"><IonIcon icon="/icons/stairs-goal.svg" color="secondary" /></Link><Link to="/icons/broken-shield"><IonIcon icon="/icons/broken-shield.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-kineticist-kinetic_knight-elemental-bastion-ex" data-hash-target><div className="box">Elemental Bastion (Ex)</div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Alters</div></div><div className="abEnd"><div className="box">Elemental defense</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Gained</div></div><div className="abEnd"><div className="box">At 2nd Level</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Ability</div></div><div className="abEnd"><div className="box">The kinetic knight becomes proficient with medium and heavy armor and shields (except tower shields). In addition, the kinetic knight can accept 1 point of burn to attune herself to a specific light or heavy shield until the next time her burn is removed. Wielding an attuned shield doesn't prevent the kinetic knight from <em>gathering power.</em></div></div></div>
<div className="abPair"><div className="abStart"><div className="box">At 4th Level</div></div><div className="abEnd"><div className="box">A kinetic knight gains the <em>elemental defense</em> ability at 4th level, rather than 2nd, and its benefits apply only while she is wearing heavy armor and wielding an attuned shield. If the kinetic knight selects the <em>expanded defense</em> talent, its benefits also apply only under these conditions.</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Special</div></div><div className="abEnd"><div className="box">If she has the <Link to="/kinetic/shroud_of_water">shroud of water</Link> defense wild talent, whenever its bonus would be increased by accepting burn, she instead increases the enhancement bonus of her armor or attuned shield by an equal amount (to a maximum of +5).</div></div></div></div>
<div className="ability p"><div className="abIcon"><Link to="/icons/stairs-goal"><IonIcon icon="/icons/stairs-goal.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-kineticist-kinetic_knight-knights-resolve-ex" data-hash-target><div className="box">Knight's Resolve (Ex)</div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Replaces</div></div><div className="abEnd"><div className="box">3rd-level infusion, supercharge</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Gained</div></div><div className="abEnd"><div className="box">At 3rd Level</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Ability</div></div><div className="abEnd"><div className="box">The kinetic knight gains the <Link to="/class/samurai">samurai's</Link> <em>resolve</em> class feature, as a samurai of her kineticist level - 2.</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">At 11th Level</div></div><div className="abEnd"><div className="box">She gains the samurai's <em>greater resolve</em> ability.</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Special</div></div><div className="abEnd"><div className="box">If she also has samurai levels, those levels stack with her kineticist levels to determine the benefits of this ability.</div></div></div></div>
</>};
const _leshykineticist = {title: "Leshykineticist", jsx: <><h2 id="arc-kineticist-leshykineticist-leshykineticist">Leshykineticist</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_wilderness">Ultimate Wilderness pg. 23</Link><br/>Of all those who pursue the path of a kineticist, only leshykineticists are both made of plant matter and born of nature spirits. These curious creatures wield ancient powers unknown to any other kineticists.</p>
<div className="sideNoteWrap startAlign singular delist"><ScrollContainer id="arc-kineticist-leshykineticist--table-0"><table><tbody><tr><ThLink scope="row" to="/icons/confirmed"><IonIcon aria-label="Prerequisites" icon="/icons/confirmed.svg" /></ThLink><td><Link to="/race/vine_leshy">Vine leshy</Link></td></tr></tbody></table></ScrollContainer></div><div className="ability p"><div className="abIcon"><Link to="/icons/info"><IonIcon icon="/icons/info.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-kineticist-leshykineticist-leshy-element" data-hash-target><div className="box">Leshy Element</div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Replaces</div></div><div className="abEnd"><div className="box">6th- and 10th-level utility wild talents, maximize metakinesis</div></div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Alters</div></div><div className="abEnd"><div className="box">Element, expanded element</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Info</div></div><div className="abEnd"><div className="box">A leshykineticist must select the wood <Link to="/ability/elements">element</Link> as her primary element and for both her <em>expanded elements.</em> She must choose <Link to="/kinetic/wood_blast">wood blast</Link> as her first simple blast and <Link to="/kinetic/positive_blast">positive blast</Link> as her second simple blast.</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">At 6th Level</div></div><div className="abEnd"><div className="box">She gains <Link to="/kinetic/green_tongue">green tongue</Link> as a bonus utility wild talent, ignoring its prerequisites.</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">At 7th Level</div></div><div className="abEnd"><div className="box">When she first gains <em>positive blast,</em> she gains <Link to="/kinetic/kinetic_healer">kinetic healer</Link> and the <Link to="/kinetic/photokinetic_infusion">photokinetic infusion</Link> instead of the extra wild talent of 3rd level or lower for expanding in the same element. Her <em>kinetic healer</em> wild talent restores 1 extra hit point per die when healing plant creatures.</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">At 9th Level</div></div><div className="abEnd"><div className="box">She gains an extra wild talent of 3rd level or lower of her choice.</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">At 10th Level</div></div><div className="abEnd"><div className="box">She gains <Link to="/kinetic/greater_green_tongue">greater green tongue</Link> as a bonus utility wild talent, ignoring its prerequisites.</div></div></div></div>
<div className="ability p"><div className="abIcon"><Link to="/icons/stairs-goal"><IonIcon icon="/icons/stairs-goal.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-kineticist-leshykineticist-basic-leshykinesis-su" data-hash-target><div className="box">Basic Leshykinesis (Su)</div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Alters</div></div><div className="abEnd"><div className="box">Basic phytokinesis</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Ability</div></div><div className="abEnd"><div className="box">A vine leshy leshykineticist can use her <em>basic phytokinesis</em> to move while in her alternate vine form, with a base speed of 10 feet and a climb speed of 10 feet. The vine counts as a prehensile appendage for the purpose of aiming kinetic blasts and <em>gathering power.</em></div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Special</div></div><div className="abEnd"><div className="box">At the GM's discretion, this ability might apply to leshykineticists of other leshy varieties as long as their alternate forms aren't rooted to the ground (and even then, they might be able to use something like a branch to aim kinetic blasts).</div></div></div></div>
<div className="ability p"><div className="abIcon"><Link to="/icons/stairs-goal"><IonIcon icon="/icons/stairs-goal.svg" color="secondary" /></Link><Link to="/icons/broken-shield"><IonIcon icon="/icons/broken-shield.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-kineticist-leshykineticist-photosynthetic-buffer" data-hash-target><div className="box">Photosynthetic Buffer</div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Alters</div></div><div className="abEnd"><div className="box">Internal buffer</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Ability</div></div><div className="abEnd"><div className="box">A leshykineticist fills her <em>buffer</em> with energy photosynthesized from sunlight, rather than from internal energy. Once per day, she can spend 1 hour motionless in her alternate plant form soaking in sunlight to fill her <em>internal buffer.</em> However, she can't fill her <em>internal buffer</em> by accepting burn, and her <em>internal buffer</em> becomes empty whenever her burn is removed.</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Special</div></div><div className="abEnd"><div className="box">She can't benefit from any abilities that increase the maximum burn her <em>buffer</em> can hold.</div></div></div></div>
<div className="ability p"><div className="abIcon"><Link to="/icons/upgrade"><IonIcon icon="/icons/upgrade.svg" color="secondary" /></Link><Link to="/icons/armor-upgrade"><IonIcon icon="/icons/armor-upgrade.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-kineticist-leshykineticist-green-rebirth-su" data-hash-target><div className="box">Green Rebirth (Su)</div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Replaces</div></div><div className="abEnd"><div className="box">Omnikinesis</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Gained</div></div><div className="abEnd"><div className="box">At 20th Level</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Ability</div></div><div className="abEnd"><div className="box">A leshykineticist taps into the ancient power of the First World. When her <em>verdant burst</em> ability activates, it heals all allies and plant creatures in the area as if by a maximized version of her <em>kinetic healer</em> ability, rather than only 1d8 hit points. After 24 hours, one of the plants that grew in the area serves as a vessel for the leshykineticist's spirit again, allowing her to return to life without penalty. Killing all the new plants that grew from her <em>verdant burst</em> within 24 hours prevents her from reviving in this way.</div></div></div></div>
</>};
const _overwhelming_soul = {title: "Overwhelming Soul", jsx: <><h2 id="arc-kineticist-overwhelming_soul-overwhelming-soul">Overwhelming Soul</h2>
<p><strong>Sources</strong> <Link to="/source/occult_adventures">Occult Adventures pg. 91</Link><br/>Some kineticists have such a powerful personality that they can seize control of their element with their minds alone, without endangering their bodies.</p>
<div className="ability p"><div className="abIcon"><Link to="/icons/upgrade"><IonIcon icon="/icons/upgrade.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-kineticist-overwhelming_soul-mind-over-matter-ex" data-hash-target><div className="box">Mind Over Matter (Ex)</div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Alters</div></div><div className="abEnd"><div className="box">Key ability score of wild talents</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Ability</div></div><div className="abEnd"><div className="box">An overwhelming soul uses her Charisma modifier instead of her Constitution modifier to determine her damage with wild talents, the DCs of Constitution-based wild talents, the duration of wild talents with a Constitution-based duration, her bonus on <Link to="/rule/concentration">concentration</Link> checks for wild talents, and the other Constitution-based effects of all her wild talents.</div></div></div></div>
<div className="ability p"><div className="abIcon"><Link to="/icons/skills"><IonIcon icon="/icons/skills.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-kineticist-overwhelming_soul-undefined" data-hash-target><div className="box">Class Skills</div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Alters</div></div><div className="abEnd"><div className="box">Class skills</div></div></div><div className="abPair"><div className="abStart"><div className="box">New Class Skills</div></div><div className="abEnd"><div className="box"><Link to="/skill/bluff">Bluff</Link> (CHA), <Link to="/skill/diplomacy">Diplomacy</Link> (CHA)</div></div></div></div>
<div className="ability p"><div className="abIcon"><Link to="/icons/armor-upgrade"><IonIcon icon="/icons/armor-upgrade.svg" color="secondary" /></Link><Link to="/icons/broken-shield"><IonIcon icon="/icons/broken-shield.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-kineticist-overwhelming_soul-mental-prowess-su" data-hash-target><div className="box">Mental Prowess (Su)</div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Replaces</div></div><div className="abEnd"><div className="box">Internal buffer</div></div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Alters</div></div><div className="abEnd"><div className="box">Burn</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Ability</div></div><div className="abEnd"><div className="box">An overwhelming soul's mind is strong enough to protect her body from the stress of channeling the elements. However, in exchange, she is unable to push her limits quite as far as other kineticists. She can't choose to accept burn, though she can use wild talents with a burn cost if she can reduce that cost to 0 points with abilities such as <em>gather power</em> and <em>infusion specialization.</em> If she would be forced to accept burn against her will (for example, if she fails a concentration check), instead of taking burn she takes 1 temporary <Link to="/rule/negative_level">negative level</Link>, which never kills her and can't be removed with <Link to="/spell/restoration">restoration</Link> or <Link to="/spell/greater_restoration">greater restoration</Link>, but which disappears automatically after 24 hours.</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">At 6th Level</div></div><div className="abEnd"><div className="box">Once per day, she can reduce the total burn cost of any wild talent by 1.</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">At 10th Level</div></div><div className="abEnd"><div className="box">She can reduce the burn cost 2 times per day.</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">At 14th Level</div></div><div className="abEnd"><div className="box">She can reduce the burn cost 3 times per day.</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">At 18th Level</div></div><div className="abEnd"><div className="box">She can reduce the burn cost 4 times per day.</div></div></div></div>
<div className="ability p"><div className="abIcon"><Link to="/icons/upgrade"><IonIcon icon="/icons/upgrade.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-kineticist-overwhelming_soul-overwhelming-power-ex" data-hash-target><div className="box">Overwhelming Power (Ex)</div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Replaces</div></div><div className="abEnd"><div className="box">Elemental overflow</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Gained</div></div><div className="abEnd"><div className="box">At 3rd Level</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Passive Ability</div></div><div className="abEnd"><div className="box">An overwhelming soul gains a bonus on attack rolls and damage rolls with her kinetic blasts. This bonus is equal to <Link to="/misc/one_third">one-third</Link> of her kineticist level. The damage bonus doesn't apply to <Link to="/kinetic/kinetic_blade">kinetic blade</Link>, <Link to="/kinetic/kinetic_whip">kinetic whip</Link>, or other infusions that don't apply the damage bonus from <em>elemental overflow.</em></div></div></div></div>
</>};
const _psammokinetic = {title: "Psammokinetic", jsx: <><h2 id="arc-kineticist-psammokinetic-psammokinetic">Psammokinetic</h2>
<p><strong>Sources</strong> <Link to="/source/heroes_from_the_fringe">Heroes from the Fringe pg. 6</Link><br/>Psammokinetics are ascetic kineticists who consider the harsh nature of the burning deserts of Osirion to be a tempering fire that can purify all their imperfections. Trained by the Pahmet dwarves, who also make up the majority of their numbers, these kineticists seek to master the powers of sand and wind while focusing on self-improvement.</p>
<div className="ability p"><div className="abIcon"><Link to="/icons/hazard-sign"><IonIcon icon="/icons/hazard-sign.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-kineticist-psammokinetic-alignment" data-hash-target><div className="box">Alignment</div></div>
<div className="abPair"><div className="abStart"><div className="box">Info</div></div><div className="abEnd"><div className="box">A psammokinetic kineticist must be lawful in alignment. If the psammokinetic ever becomes nonlawful, she cannot gain any additional levels with this archetype and loses access to the <em>ki pool</em> class feature granted by this archetype.</div></div></div></div>
<div className="ability p"><div className="abIcon"><Link to="/icons/info"><IonIcon icon="/icons/info.svg" color="secondary" /></Link><Link to="/icons/stairs-goal"><IonIcon icon="/icons/stairs-goal.svg" color="secondary" /></Link><Link to="/icons/broken-shield"><IonIcon icon="/icons/broken-shield.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-kineticist-psammokinetic-burning-winds-su" data-hash-target><div className="box">Burning Winds (Su)</div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Alters</div></div><div className="abEnd"><div className="box">Elemental focus</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">ability</div></div><div className="abEnd"><div className="box"><p>A psammokinetic must select air as her <Link to="/ability/elements">elemental focus</Link>. In place of the <Link to="/kinetic/air_blast">air blast</Link> and <Link to="/kinetic/electric_blast">electric blast</Link> normally granted to an aerokinetic, the psammokinetic gains a <em>sand blast</em> or <em>sirocco blast.</em> Except as noted below, <em>sand blast</em> functions as <em>air blast,</em> and <em>sirocco blast</em> functions as <em>electric blast</em> (including when determining what infusion wild talents the psammokinetic can use with each blast). The psammokinetic is also treated as having the fire element type for the purposes of meeting the prerequisites for the <Link to="/kinetic/cold_adaptation">cold adaptation</Link>, <Link to="/kinetic/flame_shield">flame shield</Link>, <Link to="/kinetic/heat_adaptation">heat adaptation</Link>, and <Link to="/kinetic/heat_wave">heat wave</Link> utility wild talents.</p>
<blockquote>
<p><strong className="hl">Sand Blast</strong><br/><strong>Element</strong> air; <strong>Type</strong> simple blast (Sp); <strong>Level</strong> -; <strong>Burn</strong> 0<br/><strong>Blast Type</strong> physical; <strong>Damage</strong> slashing<br/>You slice at a single foe with a stream of sand.</p>
<p><strong className="hl">Sirocco Blast</strong><br/><strong>Element</strong> air; <strong>Type</strong> simple blast (Sp); <strong>Level</strong> -; <strong>Burn</strong> 0<br/><strong>Blast Type</strong> energy; <strong>Damage</strong> fire<br/>You shoot a wave of superheated air to burn a single foe.</p>
</blockquote>
</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Special</div></div><div className="abEnd"><div className="box">A psammokinetic cannot take the <Link to="/kinetic/chain">chain</Link>, <Link to="/kinetic/magnetic_infusion">magnetic infusion</Link>, or <Link to="/kinetic/thundering_infusion">thundering infusion</Link> wild talents or the <Link to="/kinetic/aerial_adaptation">aerial adaptation</Link> or <Link to="/kinetic/celerity">celerity</Link> utility wild talents.</div></div></div></div>
<div className="ability p"><div className="abIcon"><Link to="/icons/stairs-goal"><IonIcon icon="/icons/stairs-goal.svg" color="secondary" /></Link><Link to="/icons/upgrade"><IonIcon icon="/icons/upgrade.svg" color="secondary" /></Link><Link to="/icons/armor-upgrade"><IonIcon icon="/icons/armor-upgrade.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-kineticist-psammokinetic-ki-pool-su" data-hash-target><div className="box">Ki Pool (Su)</div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Replaces</div></div><div className="abEnd"><div className="box">Elemental overflow</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Gained</div></div><div className="abEnd"><div className="box">At 3rd Level</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Ability</div></div><div className="abEnd"><div className="box"><p>A psammokinetic gains a pool of ki points, supernatural energy she can use to accomplish amazing feats. The number of points in a psammokinetic's <em>ki pool</em> is equal to <Link to="/misc/half">half</Link> her kineticist level plus her Constitution modifier. As long as she has at least 1 point in her <em>ki pool,</em> she gains a bonus on damage rolls with kinetic blasts. This bonus is equal to one-third of her kineticist level. The <em>kinetic blade</em> infusion does not add the bonus damage from this ability.</p>
<p>By spending 1 point from her <em>ki pool</em> as a <strong className="hl">swift action</strong>, a psammokinetic can do one of the following:</p>
<ul>
<li>Double her bonus (if any) on damage rolls for having at least 1 point in her <em>ki pool,</em> and gain a bonus on attack rolls with her kinetic blasts. This bonus is equal to one-third of her kineticist level. This effect remains for 1d4 rounds.</li>
<li>Gain a +2 dodge bonus to AC for 1 round.</li>
<li>Increase her base speed by 20 feet for 1 round.</li>
</ul>
<p>The <em>ki pool</em> is replenished each morning after 8 hours of rest or meditation; these hours do not need to be consecutive. If the psammokinetic has levels in another class that grants points to a pool of ki points, her psammokinetic levels stack with the levels of that class to determine the total number of ki points in the combined pool, but only one ability score modifier is added to the total. The choice of which score to use is made when the second class ability is gained, and once made, the choice cannot be changed. The psammokinetic can use ki points from this pool to power the abilities of every class she has that grants a <em>ki pool.</em></p>
</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">At 7th Level</div></div><div className="abEnd"><div className="box">As long as she has at least 1 point in her <em>ki pool,</em> her <em>sand blast</em> is treated as cold iron for the purpose of overcoming damage reduction (regardless of what infusion it is used with).</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">At 10th Level</div></div><div className="abEnd"><div className="box">Her <em>sand blast</em> is treated as a lawful weapon.</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">At 16th Level</div></div><div className="abEnd"><div className="box">Her <em>sand blast</em> is treated as <Link to="/eq-material/adamantine">adamantine</Link> for the purpose of overcoming damage reduction and bypassing hardness.</div></div></div></div>
<div className="ability p"><div className="abIcon"><Link to="/icons/info"><IonIcon icon="/icons/info.svg" color="secondary" /></Link><Link to="/icons/upgrade"><IonIcon icon="/icons/upgrade.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-kineticist-psammokinetic-sand-element-su" data-hash-target><div className="box">Sand Element (Su)</div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Alters</div></div><div className="abEnd"><div className="box">Expanded element</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">At 7th Level</div></div><div className="abEnd"><div className="box">A psammokinetic must select the earth element as her <em>expanded element.</em> She treats her kineticist level as 2 levels lower (rather than 4 levels lower) for the purpose of determining which wild talents she can learn from the earth element.</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">At 15th Level</div></div><div className="abEnd"><div className="box">The psammokinetic must choose to expand her mastery of the air element as her <em>expanded element.</em></div></div></div></div>
</>};
const _psychokineticist = {title: "Psychokineticist", jsx: <><h2 id="arc-kineticist-psychokineticist-psychokineticist">Psychokineticist</h2>
<p><strong>Sources</strong> <Link to="/source/horror_adventures">Horror Adventures pg. 56</Link><br/>While most kineticists channel elemental power through their bodies, rare kineticists, such as <em>elemental ascetics, overwhelming souls,</em> and <em>psychokineticists</em> channel such power through their minds. Psychokineticists lack an <em>overwhelming soul's</em> strong spirit, and so this energy ravages their minds but unleashes power locked in their ruptured emotions. Sometimes a psychokineticist inadvertently unleashes his power when he experiences an outburst of strong emotion, potentially making a psychokineticist an outcast or even an accidental killer.</p>
<div className="ability p"><div className="abIcon"><Link to="/icons/skills"><IonIcon icon="/icons/skills.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-kineticist-psychokineticist-undefined" data-hash-target><div className="box">Class Skills</div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Alters</div></div><div className="abEnd"><div className="box">Class skills</div></div></div><div className="abPair"><div className="abStart"><div className="box">New Class Skills</div></div><div className="abEnd"><div className="box"><Link to="/skill/sense_motive">Sense Motive</Link> (WIS)</div></div></div></div>
<div className="ability p"><div className="abIcon"><Link to="/icons/upgrade"><IonIcon icon="/icons/upgrade.svg" color="secondary" /></Link><Link to="/icons/broken-shield"><IonIcon icon="/icons/broken-shield.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-kineticist-psychokineticist-emotional-intensity-ex" data-hash-target><div className="box">Emotional Intensity (Ex)</div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Alters</div></div><div className="abEnd"><div className="box">Class skills, key ability score of wild talents</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Ability</div></div><div className="abEnd"><div className="box">A psychokineticist uses his Wisdom modifier instead of his Constitution modifier to determine his damage with wild talents, the DCs of Constitution-based wild talents, the durations of wild talents with Constitution-based durations, his bonus on <Link to="/rule/concentration">concentration</Link> checks for wild talents, and other Constitution-based effects of all his wild talents.</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Info</div></div><div className="abEnd"><div className="box">He can't use any of his wild talents whenever he would be unable to use a spell with an <Link to="/rule/components_oa">emotion component</Link>, and if he ever gains immunity to charm, compulsion, emotion effects (even if such immunity extends only to a subcategory of these effects like fear effects or compulsion effects from creatures of certain alignments), he loses all his kineticist abilities. This includes effects that he previously activated that normally last until the next time his burn is removed, like <em>elemental defenses,</em> though he still keeps all his penalties from burn. He can always choose to ignore such immunities when he would normally gain them, even if they are granted by another class feature (such as the paladin's <em>aura of courage</em>), but once he decides whether or not to ignore an immunity he would have gained, the choice cannot be changed.</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Special</div></div><div className="abEnd"><div className="box">A psychokineticist gains <Link to="/feat/psychic_sensitivity">Psychic Sensitivity</Link> as a bonus feat.</div></div></div></div>
<div className="ability p"><div className="abIcon"><Link to="/icons/broken-shield"><IonIcon icon="/icons/broken-shield.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-kineticist-psychokineticist-mind-burn-ex" data-hash-target><div className="box">Mind Burn (Ex)</div><div className="flavor">A psychokineticist's mind strains when he overtaxes himself.</div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Alters</div></div><div className="abEnd"><div className="box">Burn</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Passive Ability</div></div><div className="abEnd"><div className="box">He takes a -2 penalty on Will saves, Wisdom checks, and Wisdom-based skill checks for each point of burn he has accepted, rather than taking nonlethal damage from burn. He can accept an amount of burn equal to his Wisdom modifier (rather than 3 + his Wisdom modifier). Otherwise, his burn works just like a normal kineticist's.</div></div></div></div>
<div className="ability p"><div className="abIcon"><Link to="/icons/broken-shield"><IonIcon icon="/icons/broken-shield.svg" color="secondary" /></Link><Link to="/icons/upgrade"><IonIcon icon="/icons/upgrade.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-kineticist-psychokineticist-mental-overflow-ex" data-hash-target><div className="box">Mental Overflow (Ex)</div><div className="flavor">A psychokineticist's elemental energy sends strange elemental humors and planar echoes through his brain instead of reshaping his body with matter from his element.</div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Alters</div></div><div className="abEnd"><div className="box">Elemental overflow</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Ability</div></div><div className="abEnd"><div className="box">Instead of gaining size bonuses to physical ability scores from <em>elemental overflow,</em> he gains alchemical bonuses to his mental ability scores in equal amounts (a +2 alchemical bonus to two mental ability scores at 6th level if he has at least 3 points of burn; a +4 alchemical bonus to one mental ability score and a +2 alchemical bonus to the other two at 11th level if he has at least 5 points of burn; and a +6 alchemical bonus to one mental ability score, a +4 alchemical bonus to another, and a +2 alchemical bonus to the last at 16th level if he has at least 7 points of burn).</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Special</div></div><div className="abEnd"><div className="box">A psychokineticist doesn't gain a chance to negate critical hits and sneak attacks based on his burn. Otherwise, his <em>elemental overflow</em> works just like a normal kineticist's.</div></div></div></div>
</>};
const _terrakineticist = {title: "Terrakineticist", jsx: <><h2 id="arc-kineticist-terrakineticist-terrakineticist">Terrakineticist</h2>
<p><strong>Sources</strong> <Link to="/source/ultimate_wilderness">Ultimate Wilderness pg. 63</Link><br/>Terrakineticists have a stunted ability that allows them to access the Elemental Planes, but they've learned how to turn this limited talent into an incredible strength by tapping into the ambient elemental nature of the land surrounding them.</p>
<div className="ability p"><div className="abIcon"><Link to="/icons/stairs-goal"><IonIcon icon="/icons/stairs-goal.svg" color="secondary" /></Link><Link to="/icons/upgrade"><IonIcon icon="/icons/upgrade.svg" color="secondary" /></Link><Link to="/icons/broken-shield"><IonIcon icon="/icons/broken-shield.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-kineticist-terrakineticist-terrakinesis" data-hash-target><div className="box">Terrakinesis</div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Alters</div></div><div className="abEnd"><div className="box">Elemental focus, kinetic blast</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Ability</div></div><div className="abEnd"><div className="box"><p>Whenever a terrakineticist gains a wild talent that isn't a universal talent, she chooses one wild talent of the appropriate level from each of the six <Link to="/ability/elements">elements</Link> (aether, air, fire, earth, water, and wood).<sup><InnerLink showBacklink="backlink-arc-kineticist-terrakineticist-fake-fn-1" id="arc-kineticist-terrakineticist-fake-fn-1" data-hash-target to="arc-kineticist-terrakineticist-fake-fn-1-target">1</InnerLink></sup> She can use wild talents of the same element that she chose in this way to meet prerequisites for these wild talents. Instead of gaining one kineticist blast, a terrakineticist chooses one simple blast from each element that has more than one simple blast.</p>
<p>When in a corresponding terrain, as determined by the ranger <Link to="/ability/favored_terrain">favored terrain</Link> categories, her element changes to the corresponding element (granting her class skills, basic utility wild talent, simple blast, and elemental defense as appropriate), and she gains all the wild talents she selected from the corresponding element.</p>
<ul>
<li>Aether corresponds to urban and the Ethereal Plane</li>
<li>Air corresponds to hill, mountain, plains, and the Plane of Air</li>
<li>Fire corresponds to desert and the Plane of Fire</li>
<li>Earth corresponds to underground and the Plane of Earth</li>
<li>Water corresponds to cold, swamp, water, and the Plane of Water</li>
<li>Wood corresponds to forest, jungle, the First World, and the Positive Energy Plane.</li>
</ul>
<p>In areas that might count as multiple types of terrain, the GM decides which element predominates, and in certain areas not covered by the ranger favored terrains (such as the upper atmosphere) or in those with strong elemental energy (like an underground temple of a fire cult), the corresponding element might differ. If the kineticist class gains additional elements, those elements also gain corresponding terrains at the GM's discretion, and the terrakineticist chooses wild talents from those elements. A terrakineticist should almost never be in a situation that doesn't correspond to any of these elements, but in such an unusual circumstance (for instance, the void of space given the standard six elements), she loses access to all her wild talents, even her universal wild talents.</p>
<p>When her element changes, she loses the benefits of all active wild talents from the previous element, even if it would usually last until the next time she recovers burn. However, time spent in other terrain still counts against the ability's duration; if she changes back again to the original element, the benefit returns only if it has any remaining duration.</p>
</div></div></div></div>
<div className="ability p"><div className="abIcon"><Link to="/icons/info"><IonIcon icon="/icons/info.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-kineticist-terrakineticist-terrakinetic-defense" data-hash-target><div className="box">Terrakinetic Defense</div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Alters</div></div><div className="abEnd"><div className="box">Elemental defense</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Gained</div></div><div className="abEnd"><div className="box">At 2nd Level</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Info</div></div><div className="abEnd"><div className="box">A terrakineticist's <em>elemental defense</em> wild talent changes with her corresponding element, just like her other wild talents. However, unlike her other wild talents, any burn she invests in one element's elemental defense carries over to her elemental defense when her element changes. For instance, if a 6th-level terrakineticist invested 2 points of burn in <Link to="/kinetic/flesh_of_stone">flesh of stone</Link> to gain 2 additional points of damage reduction and then entered a city and changed to aether, she would have 2 points of burn invested in <Link to="/kinetic/force_ward">force ward</Link> and increase the force ward's temporary hit points by 6.</div></div></div></div>
<div className="ability p"><div className="abIcon"><Link to="/icons/stairs-goal"><IonIcon icon="/icons/stairs-goal.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-kineticist-terrakineticist-expanded-terrakinesis" data-hash-target><div className="box">Expanded Terrakinesis</div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Replaces</div></div><div className="abEnd"><div className="box">Expanded element</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Gained</div></div><div className="abEnd"><div className="box">At 7th Level</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Ability</div></div><div className="abEnd"><div className="box">A terrakineticist gains both simple blasts for the element corresponding to her current terrain, if that element has two, and the composite blast associated with expanding in that element (<Link to="/kinetic/force_blast">force blast</Link>, <Link to="/kinetic/thunderstorm_blast">thunderstorm blast</Link>, <Link to="/kinetic/blue_flame_blast">blue flame blast</Link>, <Link to="/kinetic/metal_blast">metal blast</Link>, <Link to="/kinetic/ice_blast">ice blast</Link>, and <Link to="/kinetic/verdant_blast">verdant blast</Link>). She also gains a universal infusion or utility talent for which she meets the prerequisites.</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">At 15th Level</div></div><div className="abEnd"><div className="box">She gains one infusion or utility wild talent for which she meets the prerequisites.</div></div></div></div>
<div className="ability p"><div className="abIcon"><Link to="/icons/magic-swirl"><IonIcon icon="/icons/magic-swirl.svg" color="secondary" /></Link></div>
<div className="title abSingle" id="arc-kineticist-terrakineticist-omniterrakinesis-su" data-hash-target><div className="box">Omniterrakinesis (Su)</div></div>
<div className="abPair"><div className="abStart"><div className="box hl">Replaces</div></div><div className="abEnd"><div className="box">Omnikinesis</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Gained</div></div><div className="abEnd"><div className="box">At 20th Level</div></div></div>
<div className="abPair"><div className="abStart"><div className="box">Ability</div></div><div className="abEnd"><div className="box">A terrakineticist can accept 1 point of burn as a <strong className="hl">free action</strong> at the start of her turn to change her element without regard to the surrounding terrain until the beginning of her next turn.</div></div></div></div>
<section data-footnotes><h3 id="arc-kineticist-terrakineticist-label">Footnotes</h3><ol>
<li id="arc-kineticist-terrakineticist-fake-fn-1-target"><p>This archetype was introduced before the <em>void</em> element was created. Consult your GM if you wish to use that element, too. As a suggestion, consider terrains such as the lowest levels of the Darklands, outer space, the Shadow Plane, and the Negative Energy Plane. <InnerLink aria-label="Back to reference 1" id="backlink-arc-kineticist-terrakineticist-fake-fn-1" data-hash-target to="arc-kineticist-terrakineticist-fake-fn-1">↩</InnerLink></p></li>
</ol></section></>};
export default {aquakinetcist:_aquakinetcist,arakineticist:_arakineticist,blightburner:_blightburner,blighted_defiler:_blighted_defiler,blood_kineticist:_blood_kineticist,cinderlands_adept:_cinderlands_adept,dark_elementalist:_dark_elementalist,elemental_annihilator:_elemental_annihilator,elemental_ascetic:_elemental_ascetic,elemental_purist:_elemental_purist,elysiokineticist:_elysiokineticist,ioun_kineticist:_ioun_kineticist,kinetic_chirurgeon:_kinetic_chirurgeon,kinetic_knight:_kinetic_knight,leshykineticist:_leshykineticist,overwhelming_soul:_overwhelming_soul,psammokinetic:_psammokinetic,psychokineticist:_psychokineticist,terrakineticist:_terrakineticist}